import React from 'react';
import { render, screen, fireEvent, waitFor } from '@testing-library/react';
import ScheduleEventModal from './ScheduleEventModal';
import { describe, test, expect } from 'vitest';

// Helpers
function makeTrainer(id: string, firstName = 'Mario', lastName = 'Rossi') {
  return { id, firstName, lastName, certifications: [] };
}

function makeCourse(id: string, title: string, duration: number) {
  return { id, title, duration, certifications: [], riskLevel: 'BASSO', courseType: 'PRIMO_CORSO' } as any;
}

describe('ScheduleEventModal - validazione durata (somma ore = durata corso)', () => {
  const trainers = [makeTrainer('t1')];
  const companies: any[] = [];
  const persons: any[] = [];

  test('disabilita Avanti quando la somma ore non coincide e lo abilita quando coincide', async () => {
    const course = makeCourse('c1', 'Corso Sicurezza', 8);

    const existingEvent = {
      id: 's1',
      training_id: 'c1',
      course: course,
      // 09:00 -> 12:00 = 3h (non coincide con 8h)
      dates: [
        { date: '2025-01-15', start: '09:00', end: '12:00', trainer_id: 't1', co_trainer_id: '' }
      ],
      location: 'Aula 1',
      max_participants: 10,
      notes: '',
      delivery_mode: 'in-person',
      risk_level: 'BASSO',
      course_type: 'PRIMO_CORSO',
    } as any;

    render(
      <ScheduleEventModal
        trainings={[course]}
        trainers={trainers as any}
        companies={companies as any}
        persons={persons as any}
        existingEvent={existingEvent}
        onClose={() => {}}
        onSuccess={() => {}}
      />
    );

    // "Avanti" deve essere disabilitato (3h != 8h)
    const nextBtn = await screen.findByRole('button', { name: /Avanti/i });
    expect(nextBtn).toBeDisabled();

    // Verifichiamo anche il messaggio di warning ore (dal DateTimeManager)
    expect(
      screen.getByText(/le ore selezionate non coincidono con la durata del corso/i)
    ).toBeInTheDocument();

    // Correggiamo l'orario fine a 17:00 per ottenere 8h totali (09:00 -> 17:00)
    const endTimeInput = screen.getByDisplayValue('12:00') as HTMLInputElement;
    fireEvent.change(endTimeInput, { target: { value: '17:00' } });

    await waitFor(() => {
      // Il bottone "Avanti" deve diventare abilitato quando la somma ore coincide con la durata
      expect(nextBtn).not.toBeDisabled();
    });

    // Verifica UI riepilogo ore
    expect(await screen.findByText(/Ore selezionate:/)).toBeInTheDocument();
    expect(screen.getByText(/Durata corso:/)).toBeInTheDocument();
    expect(screen.getByText(/Ore rimanenti:/)).toBeInTheDocument();

    // Dopo la correzione, il messaggio di attenzione non dovrebbe apparire
    expect(screen.queryByText(/Attenzione: le ore selezionate non coincidono/)).not.toBeInTheDocument();
  });
});

import React, { useState, useEffect, useCallback, useMemo } from "react";
import { Button } from "../../design-system/atoms/Button";
import { create, update } from '../../services/apiClient';
import { toast } from 'react-toastify';
import 'react-toastify/dist/ReactToastify.css';
import type { ScheduleEventModalProps } from './ScheduleEventModal.lazy';
import { apiGet } from '../../services/api';
import { Label } from "../../design-system/atoms/Label";
import { getTrainers } from "../../services/trainers";
import Modal from "../../design-system/molecules/Modal/Modal";
import GroupedCoursesService from "../../services/groupedCourses";

// Import modular components
import {
  CourseDetailsForm,
  CompanyEmployeeSelector,
  AttendanceManager,
  DocumentManager,
  DateTimeManager
} from './components';

import { normalizeText as normalizeTextUtil, expandTerms as expandTermsUtil, extractCourses as extractCoursesUtil, timeStringToMinutes as timeStringToMinutesUtil, formatDate as formatDateUtil, computeTrainerCertFilter, filterTrainersByCerts, computeTotalSelectedMinutes, buildSchedulePayload as buildSchedulePayloadUtil, validateScheduleForm, toIdString, getPersonIdsForCompanyUniversal } from './utils';
import { useDynamicRiskAndTypeOptions } from './hooks/useDynamicRiskAndTypeOptions';
import { useAutoSelectVariant } from './hooks/useAutoSelectVariant';
import { useRequiredCerts } from './hooks/useRequiredCerts';
import { useAttendance } from './hooks/useAttendance';
import { useScheduleSteps } from './hooks/useScheduleSteps';
import { useFormData } from './hooks/useFormData';
import { useSelections } from './hooks/useSelections';
import { useCourseVariants } from './hooks/useCourseVariants';
type Person = import('./utils').Person;

type Trainer = import('./utils').Trainer;

type Training = import('./utils').Training;

// Invece della definizione locale, alias al tipo condiviso
type DateEntry = import('./utils').ScheduleDateEntry;

const DELIVERY_MODES = [
  { value: 'in-person', label: 'In presenza' },
  { value: 'online', label: 'Online' },
  { value: 'hybrid', label: 'Ibrido' },
  { value: 'blended', label: 'Blended' }
];

const RISK_LEVEL_OPTIONS = [
  { value: 'ALTO', label: 'Alto' },
  { value: 'MEDIO', label: 'Medio' },
  { value: 'BASSO', label: 'Basso' },
  { value: 'A', label: 'A' },
  { value: 'B', label: 'B' },
  { value: 'C', label: 'C' },
];

const COURSE_TYPE_OPTIONS = [
  { value: 'PRIMO_CORSO', label: 'Primo corso' },
  { value: 'AGGIORNAMENTO', label: 'Aggiornamento' },
];

// Funzioni e sinonimi sono centralizzati in utils; usiamo alias locali per non cambiare il resto del codice
const normalizeText = normalizeTextUtil;
const expandTerms = expandTermsUtil;

export default function ScheduleEventModal({ 
   trainings, 
   trainers, 
   companies, 
   persons, 
   existingEvent = {}, 
   onClose, 
   onSuccess, 
   initialDate, 
   initialTime 
 }: ScheduleEventModalProps): JSX.Element {
  const [fallbackTrainers, setFallbackTrainers] = useState<Trainer[]>([]);
  const effectiveTrainers = useMemo(() => (trainers && trainers.length > 0 ? trainers : fallbackTrainers), [trainers, fallbackTrainers]);

  useEffect(() => {
    let isCancelled = false;
    if (!trainers || trainers.length === 0) {
      (async () => {
        try {
          const items = await getTrainers();
          if (!isCancelled) setFallbackTrainers(items || []);
        } catch (e) {
          // ignore
        }
      })();
    }
    return () => { isCancelled = true; };
  }, [trainers]);

  // Core state
  const isEditing = existingEvent && Object.keys(existingEvent).length > 0;
  const [loading, setLoading] = useState(false);
  const [hasScheduled, setHasScheduled] = useState(isEditing);
  const [scheduleId, setScheduleId] = useState<string | number | null>((existingEvent as Record<string, unknown>)?.id as string | number || null);

  // Initialize course variants hook
  const { selectedCourseVariants, selectedCourseDetails, setSelectedCourseDetails } = useCourseVariants({
    selectedCourse: trainings.find(t => t.id === (existingEvent as any)?.training_id),
    trainings,
  });

  // Initialize selections hook
  const {
    selectedCompanies,
    selectedPersons,
    setSelectedCompanies,
    setSelectedPersons,
    handleCompanyToggle,
    handlePersonToggle,
    handleSelectAllPersons,
    handleDeselectAllPersons,
    getPersonIdsForCompany,
  } = useSelections({
    existingEvent,
    persons,
  });

  // Initialize form data hook
  const {
    formData,
    setFormData,
    handleFormDataChange,
  } = useFormData({
    existingEvent,
    isEditing,
    initialDate,
    initialTime,
    selectedCourse: selectedCourseDetails,
    dynamicRiskOptions: RISK_LEVEL_OPTIONS,
    dynamicCourseTypeOptions: COURSE_TYPE_OPTIONS,
  });

  // Attendance state
  const { attendance, setAttendance, handleAttendanceChange, handleSelectAllForDate, handleSelectNoneForDate } = useAttendance(selectedPersons, existingEvent);
  const [status, setStatus] = useState('Preventivo');
  const [error, setError] = useState<string | null>(null);

  // Search states
  const [courseSearch, setCourseSearch] = useState('');
  const [companySearch, setCompanySearch] = useState('');
  const [personSearch, setPersonSearch] = useState('');
  const [personTab, setPersonTab] = useState<string | number>('');
  const [selectedDayIdx, setSelectedDayIdx] = useState(0);
  const [showStatusMenu, setShowStatusMenu] = useState(false);

  // Computed values
  const selectedCourse = useMemo(() => 
    selectedCourseDetails ?? trainings.find(t => t.id === formData.training_id), 
    [selectedCourseDetails, trainings, formData.training_id]
  );

  // Correggi tipi impliciti in filtri/mappe
  // Dynamic options for Risk/Type based on grouped variants (macro-corso)
  const [dynamicRiskOptions, setDynamicRiskOptions] = useState(RISK_LEVEL_OPTIONS);
  const [dynamicCourseTypeOptions, setDynamicCourseTypeOptions] = useState(COURSE_TYPE_OPTIONS);
  const { riskOpts, typeOpts, riskValid, typeValid, titleEmpty } = useDynamicRiskAndTypeOptions({
    selectedCourse,
    selectedCourseVariants,
    trainings: trainings as any[],
    risk_level: formData.risk_level as string,
    course_type: formData.course_type as string,
    normalizeText,
    baseRiskOptions: RISK_LEVEL_OPTIONS,
    baseTypeOptions: COURSE_TYPE_OPTIONS,
  });
  useEffect(() => {
    setDynamicRiskOptions(riskOpts);
    setDynamicCourseTypeOptions(typeOpts);
    if (!titleEmpty) {
      if (!riskValid && formData.risk_level) setFormData(prev => ({ ...prev, risk_level: '' }));
      if (!typeValid && formData.course_type) setFormData(prev => ({ ...prev, course_type: '' }));
    }
  }, [riskOpts, typeOpts, riskValid, typeValid, titleEmpty, formData.risk_level, formData.course_type]);

  // Auto-select the specific training variant when filters (risk/type) identify a unique match
  useAutoSelectVariant({
    selectedCourse,
    selectedCourseVariants,
    trainings: trainings as any[],
    current: { training_id: formData.training_id as any, risk_level: formData.risk_level as string, course_type: formData.course_type as string },
    normalizeText,
    riskOptions: dynamicRiskOptions,
    typeOptions: dynamicCourseTypeOptions,
    onResolve: (id, details) => {
      if (String(formData.training_id) !== String(id)) {
        setFormData(prev => ({ ...prev, training_id: id as any }));
      }
      if (details) setSelectedCourseDetails(details as any);
    }
  });

  const requiredCerts = useRequiredCerts({
    selectedCourse,
    selectedCourseVariants,
    trainings: trainings as any[],
    risk_level: formData.risk_level as string,
    course_type: formData.course_type as string,
    normalizeText,
  });

  const trainerCertFilter = useMemo(() => computeTrainerCertFilter(selectedCourse, selectedCourseVariants, trainings, formData, normalizeText, expandTerms), [selectedCourse, selectedCourseVariants, trainings, formData.risk_level, formData.course_type]);

  const filteredTrainers = useMemo(() =>
    filterTrainersByCerts(effectiveTrainers, trainerCertFilter, normalizeText)
  , [effectiveTrainers, trainerCertFilter]);

  const allCoTrainers = useMemo(() => effectiveTrainers, [effectiveTrainers]);

  // Derived hours for validation
  const timeStringToMinutes = timeStringToMinutesUtil;

  const totalSelectedMinutes = useMemo(() => computeTotalSelectedMinutes(formData.dates, timeStringToMinutes), [formData.dates, timeStringToMinutes]);

  const totalSelectedHours = useMemo(() => Math.round((totalSelectedMinutes / 60) * 100) / 100, [totalSelectedMinutes]);

  const courseDuration = useMemo(() => {
    const dur = selectedCourse?.duration;
    if (typeof dur === 'number') return dur;
    if (typeof dur === 'string') {
      const parsed = parseFloat(dur.replace(',', '.'));
      return isNaN(parsed) ? 0 : parsed;
    }
    return 0;
  }, [selectedCourse]);

  const hoursLeft = useMemo(() => {
    if (!courseDuration) return 0;
    const left = courseDuration - totalSelectedHours;
    return Math.round(left * 100) / 100;
  }, [courseDuration, totalSelectedHours]);

  // Auto-fill risk/course type if defined on course
  useEffect(() => {
    if (!selectedCourse) return;
    setFormData(prev => {
      const updates: Record<string, unknown> = {};
      if (!prev.risk_level && selectedCourse.riskLevel) updates.risk_level = selectedCourse.riskLevel;
      if (!prev.course_type && selectedCourse.courseType) updates.course_type = selectedCourse.courseType;
      return Object.keys(updates).length ? { ...prev, ...updates } : prev;
    });
  }, [selectedCourse]);

  // Auto-select risk/type when only one option is available; clear when none
  useEffect(() => {
    // Risk
    if ((dynamicRiskOptions?.length || 0) === 1 && !formData.risk_level) {
      setFormData(prev => ({ ...prev, risk_level: dynamicRiskOptions[0].value }));
    } else if ((dynamicRiskOptions?.length || 0) === 0 && formData.risk_level) {
      setFormData(prev => ({ ...prev, risk_level: '' }));
    }
    // Course type
    if ((dynamicCourseTypeOptions?.length || 0) === 1 && !formData.course_type) {
      setFormData(prev => ({ ...prev, course_type: dynamicCourseTypeOptions[0].value }));
    } else if ((dynamicCourseTypeOptions?.length || 0) === 0 && formData.course_type) {
      setFormData(prev => ({ ...prev, course_type: '' }));
    }
  }, [dynamicRiskOptions, dynamicCourseTypeOptions]);

  // Steps state and helpers
  const { currentStep, setCurrentStep, isStep0Valid, isStep1Valid, stepItems, handleNext: _handleNextHook, handleBack: _handleBackHook } = useScheduleSteps({
    formData,
    selectedCompanies,
    selectedPersons,
    dynamicRiskOptions,
    dynamicCourseTypeOptions
  });
  // Form handlers (usa handleFormDataChange dall'hook useFormData)

  // Date/time handlers
  const handleUpdateDateTime = useCallback((idx: number, field: 'date' | 'start' | 'end' | 'trainerId' | 'coTrainerId', value: string) => {
    setFormData(prev => {
      const dates = [...prev.dates];
      const updated = { ...dates[idx], [field]: value };
      dates[idx] = updated;
      return { ...prev, dates };
    });
  }, []);

  const handleAddDateTime = useCallback(() => {
    setFormData(prev => ({
      ...prev,
      dates: [
        ...prev.dates,
        {
          date: new Date().toISOString().split('T')[0],
          start: '09:00',
          end: '13:00',
          trainerId: '',
          coTrainerId: ''
        }
      ]
    }));
  }, []);

  const handleRemoveDateTime = useCallback((idx: number) => {
    setFormData(prev => ({
      ...prev,
      dates: prev.dates.filter((_, i) => i !== idx)
    }));
  }, []);

  // Utility functions
  const getCompanyName = useCallback((companyId: string | number) => {
    const company = companies.find(c => toIdString(c.id) === toIdString(companyId));
return (company?.ragioneSociale || (company as any)?.name) || 'Azienda sconosciuta';
  }, [companies]);
  const formatDate = formatDateUtil;

  // Company/Employee handlers
  // Usa gli handler provenienti dall'hook useSelections

  // Attendance handlers are provided by the hook

  // Validation
  const validateAll = useCallback(() => {
    const res = validateScheduleForm(
      {
        training_id: formData.training_id,
        risk_level: formData.risk_level as string,
        course_type: formData.course_type as string,
        location: formData.location as string,
        dates: formData.dates,
      },
      dynamicRiskOptions,
      dynamicCourseTypeOptions,
      timeStringToMinutes,
      courseDuration,
      totalSelectedHours,
    );
    if (!res.valid) {
      setError(res.error);
      return false;
    }
    setError('');
    return true;
  }, [formData, dynamicRiskOptions, dynamicCourseTypeOptions, timeStringToMinutes, courseDuration, totalSelectedHours]);

  // Navigation handlers (delegano all'hook)
  const handleNext = useCallback(() => {
    setError(null);
    _handleNextHook();
  }, [_handleNextHook]);

  const handleBack = useCallback(() => {
    setError(null);
    _handleBackHook();
  }, [_handleBackHook]);

  // Build schedule payload
  const buildSchedulePayload = useCallback(() => buildSchedulePayloadUtil(formData, selectedCompanies, selectedPersons, attendance, status, isEditing, scheduleId), [formData, selectedCompanies, selectedPersons, attendance, status, isEditing, scheduleId]);

  // Main schedule handler
  const handleSchedule = useCallback(async () => {
    setLoading(true);
    setError(null);

    try {
      if (!validateAll()) return;

      const schedulePayload = buildSchedulePayload();
      let result: { id: string | number };

      if (isEditing && scheduleId) {
        result = await update('schedules', String(scheduleId), schedulePayload) as { id: string | number };
      } else {
        result = await create('schedules', schedulePayload) as { id: string | number };
        setScheduleId(result?.id);
      }

      setHasScheduled(true);
      toast.success('Corso programmato con successo!', { 
        position: 'top-right', 
        autoClose: 2500 
      });

      if (onSuccess) onSuccess();
    } catch (err: unknown) {
      const errorMessage = err instanceof Error ? err.message : 'Errore durante la programmazione del corso';
      setError(errorMessage);
    } finally {
      setLoading(false);
    }
  }, [validateAll, buildSchedulePayload, isEditing, scheduleId, onSuccess]);

  // Prevent body scrolling when modal is open
  useEffect(() => {
    document.body.style.overflow = 'hidden';
    return () => {
      document.body.style.overflow = 'auto';
    };
  }, []);

  // Render step content
  const renderStep = () => {
    switch (currentStep) {
      case 0:
        return (
          <div className="space-y-6">
            <CourseDetailsForm
              trainings={trainings}
              trainers={effectiveTrainers}
              formData={formData}
              onFormDataChange={handleFormDataChange}
              selectedCourse={selectedCourse}
              filteredTrainers={filteredTrainers}
              coTrainerOptions={allCoTrainers}
              courseSearch={courseSearch}
              onCourseSearchChange={setCourseSearch}
              DELIVERY_MODES={DELIVERY_MODES}
              RISK_LEVEL_OPTIONS={dynamicRiskOptions}
              COURSE_TYPE_OPTIONS={dynamicCourseTypeOptions}
              onCourseSelected={(course: Training | undefined) => {
                setSelectedCourseDetails(course);
                setFormData(prev => {
                  const updates: Record<string, unknown> = {};
                  if (!prev.risk_level && course?.riskLevel) updates.risk_level = course.riskLevel;
                  if (!prev.course_type && course?.courseType) updates.course_type = course.courseType;
                  return Object.keys(updates).length ? { ...prev, ...updates } : prev;
                });
              }}
            />
            <DateTimeManager
              dates={formData.dates}
              trainers={effectiveTrainers}
              filteredTrainers={filteredTrainers}
              coTrainerOptions={allCoTrainers}
              onUpdateDateTime={handleUpdateDateTime}
              onAddDateTime={handleAddDateTime}
              onRemoveDateTime={handleRemoveDateTime}
              formatDate={formatDate}
              totalSelectedHours={totalSelectedHours}
              courseDuration={courseDuration}
              hoursLeft={hoursLeft}
            />
            <div>
              <Label>Note</Label>
              <textarea
                className="w-full p-2 border rounded resize-none"
                rows={3}
                placeholder="Note aggiuntive sul corso..."
                value={formData.notes}
                onChange={(e) => handleFormDataChange('notes', e.target.value)}
              />
            </div>
          </div>
        );

      case 1:
        return (
          <CompanyEmployeeSelector
            companies={companies}
            persons={persons}
            selectedCompanies={selectedCompanies}
            selectedPersons={selectedPersons}
            onCompanyToggle={handleCompanyToggle}
            onPersonToggle={handlePersonToggle}
            onSelectAllPersons={handleSelectAllPersons}
            onDeselectAllPersons={handleDeselectAllPersons}
            getCompanyName={getCompanyName}
            getPersonIdsForCompany={getPersonIdsForCompany}
            companySearch={companySearch}
            onCompanySearchChange={setCompanySearch}
            personSearch={personSearch}
            onPersonSearchChange={setPersonSearch}
            personTab={personTab}
            onPersonTabChange={setPersonTab}
          />
        );

      case 2:
        return (
          <AttendanceManager
            dates={formData.dates}
            selectedPersons={selectedPersons}
            persons={persons}
            attendance={attendance}
            onAttendanceChange={handleAttendanceChange}
            onSelectAllForDate={handleSelectAllForDate}
            onSelectNoneForDate={handleSelectNoneForDate}
            getCompanyName={getCompanyName}
            formatDate={formatDate}
            selectedDayIdx={selectedDayIdx}
            onSelectedDayChange={setSelectedDayIdx}
            trainers={effectiveTrainers}
            filteredTrainers={filteredTrainers}
            coTrainerOptions={allCoTrainers}
            onUpdateDateTime={handleUpdateDateTime}
          />
        );

      case 3:
        return (
          <DocumentManager
            status={status}
            onStatusChange={setStatus}
            selectedPersons={selectedPersons}
            selectedCompanies={selectedCompanies}
            attendance={attendance}
            dates={formData.dates}
            showStatusMenu={showStatusMenu}
            onShowStatusMenuChange={setShowStatusMenu}
          />
        );

      default:
        return null;
    }
  };

  return (
    <Modal
      open={true}
      onClose={onClose}
      title={isEditing ? "Modifica Programma Corso" : "Nuovo Programma Corso"}
      size="xl"
      variant="centered"
      bodyClassName="p-0"
      className="flex flex-col max-w-4xl"
      footer={
        <div className="flex justify-end gap-2 w-full">
          <Button onClick={onClose} variant="secondary">
            Annulla
          </Button>
          {currentStep > 0 && (
            <Button onClick={handleBack} variant="secondary">
              Indietro
            </Button>
          )}
          {currentStep < 3 && (
            <Button onClick={handleNext} disabled={(currentStep === 0 && !isStep0Valid) || (currentStep === 1 && !isStep1Valid)}>
              Avanti
            </Button>
          )}
          <Button onClick={handleSchedule} disabled={loading}>
            {loading ? 'Salvando...' : (isEditing ? "Aggiorna Corso" : "Programma Corso")}
          </Button>
        </div>
      }
    >
      {/* Body content moved inside Modal body */}
      <div className="p-6 flex-1 overflow-visible flex flex-col">
        {/* Navigation */}
        <div className="flex items-center justify-center space-x-2 mb-4">
          {stepItems.map((item, i) => (
            <React.Fragment key={i}>
              <div
                className={`w-8 h-8 rounded-full flex items-center justify-center text-sm font-medium cursor-pointer ${
                  i < currentStep
                    ? 'bg-green-500 text-white'
                    : i === currentStep
                    ? 'bg-blue-600 text-white'
                    : 'bg-gray-200 text-gray-600 hover:bg-gray-300'
                }`}
                onClick={() => setCurrentStep(i)}
              >
                {i < currentStep ? '✓' : i + 1}
              </div>
              {i < stepItems.length - 1 && (
                <div
                  className={`w-12 h-1 ${
                    i < currentStep ? 'bg-green-500' : 'bg-gray-200'
                  }`}
                />
              )}
            </React.Fragment>
          ))}
        </div>

        <div className="text-center mb-2">
          <h3 className="text-lg font-semibold text-gray-800">
            {stepItems[currentStep]?.label}
          </h3>
          <p className="text-sm text-gray-600">
            Passo {currentStep + 1} di {stepItems.length}
          </p>
        </div>

        {/* Error Display */}
        {error && (
          <div className="mb-3 p-3 bg-red-100 border border-red-400 text-red-700 rounded">
            {error}
          </div>
        )}

        {/* Step Content */}
        <div className="rounded-lg p-4 mb-4 flex-1 overflow-visible border border-gray-200 bg-white">
          {renderStep()}
        </div>
      </div>
    </Modal>
  );
}

import React, { useState, useEffect, useCallback, useMemo } from "react";
import { Button } from "../../design-system/atoms/Button";
// Removed unused imports: create, update, toast
import 'react-toastify/dist/ReactToastify.css';
import type { ScheduleEventModalProps } from './ScheduleEventModal.lazy';
// import { Label } from "../../design-system/atoms/Label";
import Modal from "../../design-system/molecules/Modal/Modal";
import { ScheduleModalProvider, useScheduleModalContext } from './context/ScheduleModalContext';
import ScheduleModalErrorBoundary from './components/ScheduleModalErrorBoundary';
// import { ScheduleModalLoadingState } from './components/ScheduleModalLoadingStates';

// Rimuovo import dei componenti grezzi non usati direttamente qui
// import { CourseDetailsForm, CompanyEmployeeSelector, AttendanceManager, DocumentManager, DateTimeManager } from './components';

import {
  StepCourseDetails,
  StepCompanySelection,
  StepAttendance,
  StepDocuments,
  StepDateTime
} from './components/steps';

import {
  normalizeText as normalizeTextUtil,
  expandTerms as expandTermsUtil,
  timeStringToMinutes as timeStringToMinutesUtil,
  formatDate as formatDateUtil,
  // validateScheduleForm,  // non usato qui, gestito in useScheduleSave
  toIdString,
  getPersonIdsForCompanyUniversal
} from './utils';

// import { useFormData } from './hooks/useFormData';
// import { useSelections } from './hooks/useSelections'; // non più usato
// import { useScheduleModalStateOptimized } from './hooks/useScheduleModalStateOptimized'; // non usato qui
// RIMOSSO: import { useAttendance } from './hooks/useAttendance';
import { useDynamicRiskAndTypeOptions } from './hooks/useDynamicRiskAndTypeOptions';
import { useAutoSelectVariant } from './hooks/useAutoSelectVariant';
import { useRequiredCerts } from './hooks/useRequiredCerts';
import { useScheduleSteps } from './hooks/useScheduleSteps';
import { useCourseVariants } from './hooks/useCourseVariants';
import { useScheduleSave } from './hooks/useScheduleSave';
import { useFormValidation } from './hooks/useFormValidation';
import { useNavigationHandlers } from './hooks/useNavigationHandlers';
import { useDateTimeHandlers } from './hooks/useDateTimeHandlers';
// import { useAdvancedMemoization } from './hooks/useAdvancedMemoization'; // non usato qui
import { DELIVERY_MODES, RISK_LEVEL_OPTIONS, COURSE_TYPE_OPTIONS } from '../../constants/scheduleModal';
import { useTrainerFilters } from './hooks/useTrainerFilters';
import { getTrainers } from '../../services/trainers';
import type { Training, Trainer, Option } from './types';

// Costanti importate da constants/scheduleModal.ts

const normalizeText = normalizeTextUtil;
const expandTerms = expandTermsUtil;

// Componente interno che utilizza il context
function ScheduleEventModalContent(props: ScheduleEventModalProps): JSX.Element {
  const { onClose, onSuccess, existingEvent } = props;

  // Utilizzo del context per accedere a stato e azioni
  const {
    state,
    actions,
    trainings,
    trainers,
    companies,
    persons,
    canProceedToStep,
    totalSelectedHours,
    courseDuration,
    hoursLeft,
    selectedCourse
  } = useScheduleModalContext();

  const {
    loading,
    error,
    // effectiveTrainers non fa parte dello state del context; usiamo trainers dal context
    courseSearch,
    companySearch,
    personSearch,
    personTab,
    selectedDayIdx,
    showStatusMenu,
    // status non è nel context: gestito localmente sotto
    isEditing
  } = state;

  const {
    setLoading,
    setError,
    // setHasScheduled e setScheduleId non sono nel context: gestiti localmente sotto
    setCourseSearch,
    setCompanySearch,
    setPersonSearch,
    setPersonTab,
    setSelectedDayIdx,
    setShowStatusMenu,
    // setStatus non nel context: gestito localmente
    setIsEditing
  } = actions;

  // Tipizzazione forte per setFormField
  const setFormFieldTyped = actions.setFormField as <K extends keyof typeof state.formData>(field: K, value: typeof state.formData[K]) => void;

  // Stato locale per status/scheduleId/hasScheduled (non presenti nel context)
  const [status, setStatus] = useState<string>((existingEvent?.status as string | undefined) ?? 'Preventivo');
  const [hasScheduled, setHasScheduled] = useState<boolean>(!!(existingEvent?.id as string | number | undefined));
  const [scheduleId, setScheduleId] = useState<string | number | null>((existingEvent?.id as string | number | null | undefined) ?? null);

  // Allinea il flag isEditing del context allo stato del prop existingEvent
  useEffect(() => {
    setIsEditing(!!existingEvent?.id);
  }, [existingEvent?.id, setIsEditing]);

  // Initialize course variants hook
  const { selectedCourseVariants, selectedCourseDetails, setSelectedCourseDetails } = useCourseVariants({
    selectedCourse,
    trainings,
  });

  // Alias: usa il macro-corso selezionato (selectedCourseDetails) se presente, altrimenti quello dal context
  const selectedCourseForLogic = selectedCourseDetails || selectedCourse;
  const selectedCourseForLogicNormalized = useMemo<Training | undefined>(() => (
    selectedCourseForLogic
      ? { ...selectedCourseForLogic, name: selectedCourseForLogic.title ?? selectedCourseForLogic.name ?? '' }
      : undefined
  ), [selectedCourseForLogic]);

  // Handler locale per aggiornare singoli campi del form, allineato al context
  const handleFormDataChange = useCallback(<K extends keyof typeof state.formData>(field: K, value: typeof state.formData[K]) => {
    setFormFieldTyped(field, value);
  }, [setFormFieldTyped]);

  // Attendance state
  // RIMOSSO uso di useAttendance con firma errata e non allineata al context
  // const { handleAttendanceChange, handleSelectAllForDate, handleSelectNoneForDate } = useAttendance(state.selectedPersons, state.attendance, actions.setAttendance);

  // Dynamic options for Risk/Type based on grouped variants (macro-corso)
  const [dynamicRiskOptions, setDynamicRiskOptions] = useState<Option[]>(RISK_LEVEL_OPTIONS);
  const [dynamicCourseTypeOptions, setDynamicCourseTypeOptions] = useState<Option[]>(COURSE_TYPE_OPTIONS);

  // Use computed values from context
  const formData = state.formData;
  const selectedPersons = state.selectedPersons;
  const selectedCompanies = state.selectedCompanies;
  const attendance = state.attendance;
  const setFormData = actions.setFormData;
  const handleCompanyToggle = actions.toggleCompany;
  const handlePersonToggle = actions.togglePerson;

  // Adapter locali per selezione/deselezione per azienda
  const getPersonIdsForCompany = useCallback((companyId: string) => {
    return getPersonIdsForCompanyUniversal(persons, companyId);
  }, [persons]);
  const handleSelectAllPersonsByCompany = useCallback((companyId: string | number) => {
    const ids = getPersonIdsForCompany(String(companyId));
    actions.selectAllPersons(ids);
  }, [actions, getPersonIdsForCompany]);
  const handleDeselectAllPersonsByCompany = useCallback((companyId: string | number) => {
    const idsSet = new Set(getPersonIdsForCompany(String(companyId)).map(String));
    Array.from(selectedPersons).forEach(id => {
      if (idsSet.has(String(id))) {
        actions.togglePerson(id);
      }
    });
  }, [actions, getPersonIdsForCompany, selectedPersons]);

  // Handlers Attendance allineati al context
  const handleAttendanceChange = useCallback((dateIdx: number, personId: string | number, isPresent: boolean) => {
    const id = String(personId);
    const current = (attendance[dateIdx] || []).map(String);
    const updatedForDate = isPresent
      ? Array.from(new Set([...current, id]))
      : current.filter(pid => String(pid) !== id);
    actions.setAttendance(dateIdx, updatedForDate);
  }, [attendance, actions]);

  const handleSelectAllForDate = useCallback((dateIdx: number) => {
    actions.setAttendance(dateIdx, Array.from(new Set(Array.from(selectedPersons).map(String))));
  }, [actions, selectedPersons]);

  const handleSelectNoneForDate = useCallback((dateIdx: number) => {
    actions.setAttendance(dateIdx, []);
  }, [actions]);

  // Fallback locale: se il context non fornisce trainer, recuperali dai servizi
  const [fallbackTrainers, setFallbackTrainers] = useState<Trainer[]>([]);
  useEffect(() => {
    if (Array.isArray(trainers) && trainers.length > 0) return;
    let cancelled = false;
    (async () => {
      try {
        const res = await getTrainers();
        if (!cancelled) setFallbackTrainers(Array.isArray(res) ? (res as Trainer[]) : []);
      } catch {
        // silenzioso: se fallisce, i dropdown resteranno disabilitati
      }
    })();
    return () => {
      cancelled = true;
    };
  }, [trainers]);

  // Trainers effettivi con fallback sicuro
  const effectiveTrainers: Trainer[] = useMemo(
    () => (Array.isArray(trainers) && trainers.length > 0 ? trainers : fallbackTrainers),
    [trainers, fallbackTrainers]
  );

  // Correzione Rules of Hooks: chiamiamo direttamente l’hook, non dentro useMemo
  const dynamicOptionsResult = useDynamicRiskAndTypeOptions({
    selectedCourse: selectedCourseForLogicNormalized,
    selectedCourseVariants,
    trainings: trainings,
    risk_level: formData.risk_level,
    course_type: formData.course_type,
    normalizeText,
    baseRiskOptions: RISK_LEVEL_OPTIONS,
    baseTypeOptions: COURSE_TYPE_OPTIONS,
  });
  const { riskOpts, typeOpts, riskValid, typeValid, titleEmpty } = dynamicOptionsResult;

  // Aggiorna le opzioni dinamiche tramite effect
  useEffect(() => {
    setDynamicRiskOptions(riskOpts);
    setDynamicCourseTypeOptions(typeOpts);
  }, [riskOpts, typeOpts]);

  // Auto-select the specific training variant when filters (risk/type) identify a unique match
  useAutoSelectVariant({
    selectedCourse: selectedCourseForLogicNormalized,
    selectedCourseVariants,
    trainings: trainings,
    current: { training_id: formData.training_id, risk_level: formData.risk_level, course_type: formData.course_type },
    normalizeText,
    riskOptions: dynamicRiskOptions,
    typeOptions: dynamicCourseTypeOptions,
    onResolve: (id: string | number, details?: Training) => {
        if (String(formData.training_id ?? '') !== String(id)) {
          setFormData({ training_id: id });
        }
        if (details) setSelectedCourseDetails(details);
      }
  });

  useRequiredCerts({
    selectedCourse: selectedCourseForLogicNormalized,
    selectedCourseVariants,
    trainings: trainings,
    risk_level: formData.risk_level,
    course_type: formData.course_type,
    normalizeText,
  });

  // Trainer filters with safe fallback to all trainers
  const { filteredTrainers, coTrainerOptions: allCoTrainers } = useTrainerFilters({
    selectedCourse: selectedCourseForLogicNormalized,
    selectedCourseVariants,
    trainings: trainings,
    formData: { risk_level: formData.risk_level, course_type: formData.course_type, training_id: formData.training_id },
    trainers: effectiveTrainers,
    normalizeText,
    expandTerms,
  });

  // Utility functions - Memoized
  const getCompanyName = useCallback((companyId: string | number) => {
    const company = companies.find(c => toIdString(c.id) === toIdString(companyId));
    return (company?.ragioneSociale || company?.name) || 'Azienda sconosciuta';
  }, [companies]);

  // Derived hours for validation - Optimized calculations
  const timeStringToMinutes = useMemo(() => timeStringToMinutesUtil, []);
  // totalSelectedMinutes/totalSelectedHours calcolati localmente sono stati rimossi;
  // utilizzare totalSelectedHours dal context per evitare redeclaration

  // Use computed values from context
  // courseDuration, totalSelectedHours, and hoursLeft are already available from context

  // Auto-fill risk/course type if defined on course - Optimized
  useEffect(() => {
    if (!selectedCourse) return;

    const updates: Partial<typeof formData> = {};
    if (!formData.risk_level && selectedCourse.riskLevel) {
      updates.risk_level = selectedCourse.riskLevel as string;
    }
    if (!formData.course_type && selectedCourse.courseType) {
      updates.course_type = selectedCourse.courseType as string;
    }

    if (Object.keys(updates).length > 0) {
      setFormData(updates);
    }
  }, [selectedCourse?.riskLevel, selectedCourse?.courseType, formData.risk_level, formData.course_type, setFormData, selectedCourse]);

  // Auto-select risk/type when only one option is available - Optimized
  useEffect(() => {
    if (!titleEmpty) {
      const updates: Partial<typeof formData> = {};
      if (!riskValid && formData.risk_level) updates.risk_level = '';
      if (!typeValid && formData.course_type) updates.course_type = '';

      if (Object.keys(updates).length > 0) {
        setFormData(updates);
      }
    }
  }, [riskValid, typeValid, titleEmpty, formData.risk_level, formData.course_type, setFormData]);

  // Risk/Type auto-selection in effect (evita side-effects durante il render)
  useEffect(() => {
    const next: Partial<typeof formData> = {};
    const riskOptionsLength = dynamicRiskOptions?.length || 0;
    if (riskOptionsLength === 1 && !formData.risk_level) {
      next.risk_level = dynamicRiskOptions[0].value;
    } else if (riskOptionsLength === 0 && formData.risk_level) {
      next.risk_level = '';
    }

    const typeOptionsLength = dynamicCourseTypeOptions?.length || 0;
    if (typeOptionsLength === 1 && !formData.course_type) {
      next.course_type = dynamicCourseTypeOptions[0].value;
    } else if (typeOptionsLength === 0 && formData.course_type) {
      next.course_type = '';
    }

    if (Object.keys(next).length > 0) {
      setFormData(next);
    }
  }, [dynamicRiskOptions, dynamicCourseTypeOptions, formData.risk_level, formData.course_type, setFormData]);

  // Steps state and helpers
  const { isStep0Valid, isStep1Valid, stepItems, handleNext: _handleNextHook, handleBack: _handleBackHook } = useScheduleSteps({
    formData: {
      ...formData,
      dates: formData.dates.map(d => ({
        ...d,
        trainerId: String(d.trainerId),
        coTrainerId: d.coTrainerId != null && d.coTrainerId !== '' ? String(d.coTrainerId) : undefined
      }))
    },
    selectedPersons: Array.from(selectedPersons),
    selectedCompanies: Array.from(selectedCompanies),
    selectedCourse: selectedCourseForLogicNormalized,
    dynamicRiskOptions,
    dynamicCourseTypeOptions,
    // currentStep removed
  });

  const currentStep = state.currentStep;

  // Form validation hook
  const { 
    isValid: formIsValid, 
    errors: formErrors, 
    fieldErrors, 
    isStep0Valid: validationStep0Valid, 
    isStep1Valid: validationStep1Valid, 
    isStep2Valid: validationStep2Valid, 
    validateCurrentStep, 
    validateField 
  } = useFormValidation({
    formData,
    dynamicRiskOptions,
    dynamicCourseTypeOptions,
    currentStep,
    selectedCourse: selectedCourseForLogicNormalized,
    courseDuration,
    totalSelectedHours,
    timeStringToMinutes,
    selectedCompanies: Array.from(selectedCompanies),
    selectedPersons: Array.from(selectedPersons)
  });

  // Form handlers
  // Adattatore tipizzato per i date handlers (accetta coTrainerId non opzionale)
  const setFormDataForDateHandlers: (updates: Partial<{
    dates: Array<{ date: string; start: string; end: string; trainerId: string | number; coTrainerId: string | number }>
  }>) => void = (updates) => {
    actions.setFormData(updates);
  };
  const { handleDateChange, handleRemoveDate } = useDateTimeHandlers({ formData, setFormData: setFormDataForDateHandlers });

  // Unified Date/Time/Trainer updater to avoid duplication across steps
  const handleUpdateDateTime = useCallback((index: number, field: 'date' | 'start' | 'end' | 'trainerId' | 'coTrainerId', value: string | number) => {
    if (field === 'date' || field === 'start' || field === 'end') {
      handleDateChange(index, field, String(value));
      return;
    }
    // trainerId / coTrainerId updates
    const newDates = formData.dates.map((date, i) =>
      i === index ? { ...date, [field]: value } : date
    );
    setFormData({ dates: newDates });
  }, [formData.dates, handleDateChange, setFormData]);

  // Navigation handlers
  const { handleNext, handleBack } = useNavigationHandlers({
    currentStep,
    setCurrentStep: actions.setCurrentStep,
    validateCurrentStep,
    setError: actions.setError,
  });

  // Save function using the new hook
  const { handleSave: saveSchedule } = useScheduleSave({
    isEditing,
    scheduleId: (existingEvent?.id as string | number) || scheduleId,
    setLoading,
    setError,
    setHasScheduled,
    setScheduleId,
    onSuccess: () => {
      onSuccess?.();
      onClose?.();
    },
    dynamicRiskOptions,
    dynamicCourseTypeOptions,
    courseDuration,
    totalSelectedHours,
    selectedCompanies: Array.from(selectedCompanies),
    status
  });

  // Save handler
  const handleSave = useCallback(async () => {
    await saveSchedule(formData, Array.from(selectedPersons), attendance);
  }, [saveSchedule, formData, selectedPersons, attendance]);

  // Render step content
  const renderStepContent = () => {
    switch (currentStep) {
      case 0:
        return (
          <StepCourseDetails
            formData={formData}
            onFormDataChange={handleFormDataChange}
            setFormData={setFormData}
            trainings={trainings}
            selectedCourse={selectedCourseForLogicNormalized}
            setSelectedCourseDetails={setSelectedCourseDetails}
            effectiveTrainers={effectiveTrainers}
            filteredTrainers={filteredTrainers}
            allCoTrainers={allCoTrainers}
            dynamicRiskOptions={dynamicRiskOptions}
            dynamicCourseTypeOptions={dynamicCourseTypeOptions}
            DELIVERY_MODES={DELIVERY_MODES}
            courseSearch={courseSearch}
            setCourseSearch={setCourseSearch}
            handleDateChange={handleDateChange}
            handleRemoveDate={handleRemoveDate}
            totalSelectedHours={totalSelectedHours}
            courseDuration={courseDuration}
            hoursLeft={hoursLeft}
            formatDate={formatDateUtil}
          />
        );
      case 1:
        return (
          <StepCompanySelection
            selectedPersons={Array.from(selectedPersons)}
            selectedCompanies={Array.from(selectedCompanies)}
            onCompanyToggle={handleCompanyToggle}
            onPersonToggle={handlePersonToggle}
            onSelectAllPersons={handleSelectAllPersonsByCompany}
            onDeselectAllPersons={handleDeselectAllPersonsByCompany}
            companySearch={companySearch}
            onCompanySearchChange={setCompanySearch}
            personSearch={personSearch}
            onPersonSearchChange={setPersonSearch}
            personTab={personTab}
            onPersonTabChange={setPersonTab}
            companies={companies}
            persons={persons}
            getPersonIdsForCompany={getPersonIdsForCompany}
            getCompanyName={getCompanyName}
          />
        );
      case 2:
        return (
          <StepAttendance
            dates={formData.dates}
            selectedPersons={Array.from(selectedPersons)}
            persons={persons}
            attendance={attendance}
            onAttendanceChange={handleAttendanceChange}
            onSelectAllForDate={handleSelectAllForDate}
            onSelectNoneForDate={handleSelectNoneForDate}
            selectedDayIdx={selectedDayIdx}
            onSelectedDayChange={setSelectedDayIdx}
            effectiveTrainers={effectiveTrainers}
            filteredTrainers={filteredTrainers}
            allCoTrainers={allCoTrainers}
            onUpdateDateTime={handleUpdateDateTime}
            formatDate={formatDateUtil}
            getCompanyName={getCompanyName}
          />
        );
      case 3:
        return (
          <StepDocuments
            status={status}
            onStatusChange={setStatus}
            selectedPersons={Array.from(selectedPersons)}
            selectedCompanies={Array.from(selectedCompanies)}
            attendance={attendance}
            dates={formData.dates}
            showStatusMenu={showStatusMenu}
            onShowStatusMenuChange={setShowStatusMenu}
          />
        );
      case 4:
        return (
          <StepDateTime
            dates={formData.dates}
            effectiveTrainers={effectiveTrainers}
            filteredTrainers={filteredTrainers}
            allCoTrainers={allCoTrainers}
            onUpdateDateTime={handleUpdateDateTime}
            onAddDateTime={() => setFormData({
              dates: [...formData.dates, { date: '', start: '09:00', end: '13:00', trainerId: '', coTrainerId: '' }]
            })}
            onRemoveDateTime={handleRemoveDate}
            totalSelectedHours={totalSelectedHours}
            courseDuration={courseDuration}
            hoursLeft={hoursLeft}
            formatDate={formatDateUtil}
          />
        );
      default:
        return null;
    }
  };

  return (
    <Modal
      isOpen={true}
      onClose={onClose}
      title={isEditing ? "Modifica Evento" : "Programma Nuovo Evento"}
      size="xl"
      bodyClassName="max-h-[calc(90vh-200px)] overflow-y-auto"
      footer={
        <div className="flex justify-between items-center w-full">
          <Button
            variant="secondary"
            onClick={onClose}
            disabled={loading}
          >
            Annulla
          </Button>

          <div className="flex space-x-3">
            {currentStep > 0 && (
              <Button
                variant="secondary"
                onClick={handleBack}
                disabled={loading}
              >
                Indietro
              </Button>
            )}

            {currentStep < stepItems.length - 1 ? (
              <Button
                variant="primary"
                onClick={handleNext}
                disabled={loading || (currentStep === 0 && !isStep0Valid) || (currentStep === 1 && !isStep1Valid)}
              >
                Avanti
              </Button>
            ) : (
              <Button
                variant="primary"
                onClick={handleSave}
                disabled={loading}
              >
                {loading ? 'Salvataggio...' : (isEditing ? 'Aggiorna' : 'Salva')}
              </Button>
            )}
          </div>
        </div>
      }
    >
      <div className="space-y-6">
        {/* Steps indicator */}
        <div className="flex items-center justify-between">
          {stepItems.map((step, index) => (
            <div
              key={`step-${index}`}
              className={`flex items-center ${index < stepItems.length - 1 ? 'flex-1' : ''}`}
            >
              <div
                className={`flex items-center justify-center w-8 h-8 rounded-full text-sm font-medium ${
                  index === currentStep
                    ? 'bg-blue-600 text-white'
                    : index < currentStep
                    ? 'bg-green-600 text-white'
                    : 'bg-gray-300 text-gray-600'
                }`}
              >
                {index + 1}
              </div>
              <span className={`ml-2 text-sm ${index === currentStep ? 'font-medium' : ''}`}>
                {step.label}
              </span>
              {index < stepItems.length - 1 && (
                <div className={`flex-1 h-0.5 mx-4 ${index < currentStep ? 'bg-green-600' : 'bg-gray-300'}`} />
              )}
            </div>
          ))}
        </div>

        {/* Error display */}
        {error && (
          <div className="bg-red-50 border border-red-200 rounded-md p-4">
            <div className="flex">
              <div className="ml-3">
                <h3 className="text-sm font-medium text-red-800">Errore</h3>
                <div className="mt-2 text-sm text-red-700">{error}</div>
              </div>
            </div>
          </div>
        )}

        {/* Step content */}
        <div className="min-h-[400px]">
          {renderStepContent()}
        </div>
      </div>
    </Modal>
  );
}

// Componente principale con error boundary e context provider
export default function ScheduleEventModal(props: ScheduleEventModalProps): JSX.Element {
  return (
    <ScheduleModalErrorBoundary>
      <ScheduleModalProvider
        trainings={props.trainings}
        trainers={props.trainers}
        companies={props.companies}
        persons={props.persons}
        existingEvent={props.existingEvent}
        initialDate={props.initialDate}
        initialTime={props.initialTime}
      >
        <ScheduleEventModalContent {...props} />
      </ScheduleModalProvider>
    </ScheduleModalErrorBoundary>
  );
}

import React from 'react';
import { Button } from '../../design-system/atoms/Button';
import Modal from '../../design-system/molecules/Modal/Modal';
import { ScheduleModalProvider, useScheduleModalContext } from './context/ScheduleModalContext';
import ScheduleModalErrorBoundary from './components/ScheduleModalErrorBoundary';
import { ScheduleModalLoadingState } from './components/ScheduleModalLoadingStates';
import type { ScheduleEventModalProps } from './ScheduleEventModal.lazy';

import { StepCourseDetailsSimple } from './components/steps/StepCourseDetailsSimple';
import { StepCompanySelectionSimple } from './components/steps/StepCompanySelectionSimple';
// Import altri step quando saranno creati
// import StepAttendanceSimple from '../shared/StepAttendanceSimple';
import StepDocumentsSimple from '../shared/StepDocumentsSimple';
import StepDateTimeSimple from '../shared/StepDateTimeSimple';

// Componente interno refactorizzato che utilizza il context
function ScheduleEventModalContentRefactored({ 
  onClose, 
  onSuccess
}: Pick<ScheduleEventModalProps, 'onClose' | 'onSuccess'>): JSX.Element {

  // Utilizzo del context per accedere a stato e azioni
  const {
    state,
    actions,
    trainings,
    trainers,
    companies,
    persons,
    canProceedToStep,
    totalSelectedHours,
    courseDuration,
    hoursLeft,
    selectedCourse
  } = useScheduleModalContext();

  const {
    formData,
    selectedPersons,
    selectedCompanies,
    attendance,
    currentStep,
    loading,
    error,
    courseSearch,
    companySearch,
    personSearch,
    personTab,
    selectedDayIdx,
    showStatusMenu,
    isEditing
  } = state;

  // Funzione per renderizzare il contenuto dello step corrente
  const renderStepContent = () => {
    switch (currentStep) {
      case 0:
        return (
          <StepCourseDetailsSimple
            formData={formData}
            trainings={trainings}
            trainers={trainers}
            selectedCourse={selectedCourse}
            courseSearch={courseSearch}
            onFormDataChange={actions.setFormField}
            onCourseSearchChange={actions.setCourseSearch}
            totalSelectedHours={totalSelectedHours}
            courseDuration={courseDuration}
            hoursLeft={hoursLeft}
          />
        );
      case 1:
        return (
          <StepCompanySelectionSimple
            companies={companies}
            selectedCompanies={selectedCompanies}
            companySearch={companySearch}
            onCompanyToggle={actions.toggleCompany}
            onCompanySearchChange={actions.setCompanySearch}
          />
        );
      case 2:
          return (
            <div className="text-center py-8">
              <p className="text-gray-500">Componente Attendance in sviluppo...</p>
            </div>
          );
      case 3:
          return (
            <StepDocumentsSimple
              documents={[]}
              selectedDocuments={[]}
              onDocumentToggle={(documentId: string) => {
                console.log('Toggle document:', documentId);
              }}
              onDocumentUpload={(file: File) => {
                console.log('Upload document:', file.name);
              }}
              onDocumentRemove={(documentId: string) => {
                console.log('Remove document:', documentId);
              }}
            />
          );
      case 4:
          return (
            <StepDateTimeSimple
               selectedDate={formData.dates?.[0]?.date || ''}
               selectedTime={formData.dates?.[0]?.start || ''}
               selectedLocation={''}
               availableTimeSlots={[]}
               locations={['Aula 1', 'Aula 2', 'Sala Conferenze']}
               onDateChange={(date: string) => {
                 const currentDate = formData.dates?.[0] || { date: '', start: '', end: '', trainerId: '', coTrainerId: '' };
                 actions.setFormField('dates', [{ ...currentDate, date }]);
               }}
               onTimeChange={(time: string) => {
                 const currentDate = formData.dates?.[0] || { date: '', start: '', end: '', trainerId: '', coTrainerId: '' };
                 actions.setFormField('dates', [{ ...currentDate, start: time }]);
               }}
               onLocationChange={(location: string) => {
                 console.log('Location changed:', location);
               }}
             />
          );
      default:
        return null;
    }
  };

  // Gestione navigazione
  const handleNext = () => {
    if (canProceedToStep(currentStep + 1)) {
      actions.setCurrentStep(currentStep + 1);
    }
  };

  const handleBack = () => {
    if (currentStep > 0) {
      actions.setCurrentStep(currentStep - 1);
    }
  };

  const handleSave = async () => {
    try {
      actions.setLoading(true);
      actions.setError(null);

      // Logica di salvataggio qui
      console.log('Saving schedule...', { formData, selectedPersons, attendance });

      // Simula salvataggio
      await new Promise(resolve => setTimeout(resolve, 1000));

      onSuccess?.();
      onClose();
    } catch (err) {
      actions.setError(err instanceof Error ? err.message : 'Errore durante il salvataggio');
    } finally {
      actions.setLoading(false);
    }
  };

  if (loading) {
    return <ScheduleModalLoadingState type="save" />;
  }

  return (
    <Modal
      isOpen={true}
      onClose={onClose}
      title="Pianifica Evento"
      size="xl"
      className="schedule-event-modal"
    >
      <div className="space-y-6">
        {/* Indicatore step */}
        <div className="flex items-center justify-between mb-6">
          <div className="flex space-x-2">
            {[0, 1, 2, 3, 4].map((step) => (
              <div
                key={step}
                className={`w-8 h-8 rounded-full flex items-center justify-center text-sm font-medium ${
                  step === currentStep
                    ? 'bg-blue-600 text-white'
                    : step < currentStep
                    ? 'bg-green-600 text-white'
                    : 'bg-gray-200 text-gray-600'
                }`}
              >
                {step + 1}
              </div>
            ))}
          </div>
          <div className="text-sm text-gray-600">
            Step {currentStep + 1} di 5
          </div>
        </div>

        {/* Errore */}
        {error && (
          <div className="bg-red-50 border border-red-200 rounded-md p-4">
            <div className="text-red-800">{error}</div>
          </div>
        )}

        {/* Contenuto step */}
        <div className="min-h-[400px]">
          {renderStepContent()}
        </div>

        {/* Bottoni navigazione */}
        <div className="flex justify-between pt-6 border-t">
          <Button
            variant="outline"
            onClick={handleBack}
            disabled={currentStep === 0}
          >
            Indietro
          </Button>

          <div className="flex space-x-3">
            <Button
              variant="outline"
              onClick={onClose}
            >
              Annulla
            </Button>

            {currentStep === 4 ? (
              <Button
                onClick={handleSave}
                disabled={loading}
              >
                {loading ? 'Salvataggio...' : 'Salva'}
              </Button>
            ) : (
              <Button
                onClick={handleNext}
                disabled={!canProceedToStep(currentStep + 1)}
              >
                Avanti
              </Button>
            )}
          </div>
        </div>
      </div>
    </Modal>
  );
}

// Componente principale refactorizzato con context provider
export default function ScheduleEventModalRefactored(props: ScheduleEventModalProps): JSX.Element {
