        expect(screen.getByText(/Errore durante il salvataggio/i)).toBeInTheDocument();
      });
    });
  });

  describe('Performance and Memoization', () => {
    it('should not re-render unnecessarily', async () => {
      const renderSpy = vi.fn();

      const TestComponent = (props: ScheduleEventModalProps) => {
        renderSpy();
        return <ScheduleEventModal {...props} />;
      };

      const { rerender } = render(<TestComponent {...defaultProps} />);

      expect(renderSpy).toHaveBeenCalledTimes(1);

      // Re-render with same props
      rerender(<TestComponent {...defaultProps} />);

      // Should use memoization to prevent unnecessary re-renders
      expect(renderSpy).toHaveBeenCalledTimes(2); // Only initial + rerender
    });

    it('should handle large datasets efficiently', async () => {
      const largeDataset = {
        ...defaultProps,
        trainings: Array.from({ length: 1000 }, (_, i) => ({
          id: i,
          name: `Corso ${i}`,
          description: `Descrizione ${i}`,
          duration: 8
        })),
        persons: Array.from({ length: 5000 }, (_, i) => ({
          id: i,
          firstName: `Nome ${i}`,
          lastName: `Cognome ${i}`,
          email: `user${i}@example.com`,
          company_id: Math.floor(i / 100)
        }))
      };

      const startTime = performance.now();
      render(<ScheduleEventModal {...largeDataset} />);
      const endTime = performance.now();

      // Should render within reasonable time (adjust threshold as needed)
      expect(endTime - startTime).toBeLessThan(1000); // 1 second
    });
  });

  describe('Accessibility', () => {
    it('should have proper ARIA labels', () => {
      render(<ScheduleEventModal {...defaultProps} />);

      expect(screen.getByRole('dialog')).toBeInTheDocument();
      expect(screen.getByLabelText(/corso/i)).toBeInTheDocument();
      expect(screen.getByLabelText(/formatore/i)).toBeInTheDocument();
    });

    it('should support keyboard navigation', async () => {
      render(<ScheduleEventModal {...defaultProps} />);

      // Tab through form elements
      await user.tab();
      expect(screen.getByLabelText(/corso/i)).toHaveFocus();

      await user.tab();
      expect(screen.getByLabelText(/formatore/i)).toHaveFocus();
    });

    it('should handle escape key to close modal', async () => {
      const mockOnClose = vi.fn();
      const props = { ...defaultProps, onClose: mockOnClose };

      render(<ScheduleEventModal {...props} />);

      await user.keyboard('{Escape}');

      expect(mockOnClose).toHaveBeenCalled();
    });
  });
});

import React from 'react';
import { Button } from '../../../design-system/atoms/Button';
import { Label } from '../../../design-system/atoms/Label';
import Select from 'react-select';

// Tipi condivisi dal dominio schedules
type DateEntry = import('../types').ScheduleDateEntry;
type Person = import('../types').Person;
type Trainer = import('../types').Trainer;

// rimosso: interface Trainer { id: string; firstName: string; lastName: string; certifications?: string[] }
interface AttendanceManagerProps {
  dates: DateEntry[];
  selectedPersons: (string | number)[];
  persons: Person[];
  attendance: Record<number, (string | number)[]>;
  onAttendanceChange: (dateIdx: number, personId: string | number, isPresent: boolean) => void;
  onSelectAllForDate: (dateIdx: number) => void;
  onSelectNoneForDate: (dateIdx: number) => void;
  getCompanyName: (companyId: string | number) => string;
  formatDate: (isoDate: string) => string;
  selectedDayIdx: number;
  onSelectedDayChange: (idx: number) => void;
  // Nuove props per gestione docenti per sessione
  trainers: Trainer[];
  filteredTrainers: Trainer[];
  coTrainerOptions: Trainer[];
  onUpdateDateTime: (idx: number, field: 'date' | 'start' | 'end' | 'trainerId' | 'coTrainerId', value: string) => void;
}

export const AttendanceManager: React.FC<AttendanceManagerProps> = ({
  dates,
  selectedPersons,
  persons,
  attendance,
  onAttendanceChange,
  onSelectAllForDate,
  onSelectNoneForDate,
  getCompanyName,
  formatDate,
  selectedDayIdx,
  onSelectedDayChange,
  trainers,
  filteredTrainers,
  coTrainerOptions,
  onUpdateDateTime
}) => {
  const getTrainerName = React.useCallback((trainerId: string | number) => {
    const trainer = trainers.find(t => String(t.id) === String(trainerId));
    return trainer ? `${trainer.firstName} ${trainer.lastName}` : '';
  }, [trainers]);

  return (
    <div className="space-y-4">
      <h3 className="font-semibold text-gray-700">Registrazione Presenze</h3>

      {/* Date Selector */}
      <div className="flex flex-wrap gap-2">
        {dates.map((dateEntry, idx) => (
          <button
            key={idx}
            type="button"
            onClick={() => onSelectedDayChange(idx)}
            className={`px-3 py-2 text-sm rounded border ${
              selectedDayIdx === idx
                ? 'bg-blue-600 text-white border-blue-600'
                : 'bg-white text-gray-700 border-gray-300 hover:bg-gray-50'
            }`}
          >
            {formatDate(dateEntry.date)}
            <div className="text-xs">
              {dateEntry.start} - {dateEntry.end}
            </div>
          </button>
        ))}
      </div>

      {/* Selezione Docenti per la data selezionata */}
      {dates[selectedDayIdx] && (
        <div className="border rounded p-4 bg-blue-50">
          <h4 className="font-medium mb-3">Docenti per {formatDate(dates[selectedDayIdx].date)}</h4>
          <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
            <div>
              <Label>Formatore Principale</Label>
              <Select
                value={filteredTrainers.find(t => String(t.id) === String(dates[selectedDayIdx].trainerId)) ? {
                  value: dates[selectedDayIdx].trainerId,
                  label: getTrainerName(dates[selectedDayIdx].trainerId)
                } : null}
                onChange={(option: any) => {
                  const newTrainerId = option ? String(option.value) : '';
                  if (newTrainerId && newTrainerId === String(dates[selectedDayIdx].coTrainerId)) {
                    onUpdateDateTime(selectedDayIdx, 'coTrainerId', '');
                  }
                  onUpdateDateTime(selectedDayIdx, 'trainerId', newTrainerId);
                }}
                options={filteredTrainers.map(t => ({
                  value: t.id,
                  label: `${t.firstName} ${t.lastName}`
                }))}
                placeholder="Seleziona formatore"
                isClearable
                classNamePrefix="react-select"
              />
            </div>
            <div>
              <Label>Co-Formatore (Opzionale)</Label>
              <Select
                value={coTrainerOptions.find(t => String(t.id) === String(dates[selectedDayIdx].coTrainerId)) ? {
                  value: dates[selectedDayIdx].coTrainerId,
                  label: getTrainerName(dates[selectedDayIdx].coTrainerId)
                } : null}
                onChange={(option: any) => {
                  onUpdateDateTime(selectedDayIdx, 'coTrainerId', option ? String(option.value) : '');
                }}
                options={coTrainerOptions
                  .filter(t => String(t.id) !== String(dates[selectedDayIdx].trainerId))
                  .map(t => ({
                    value: t.id,
                    label: `${t.firstName} ${t.lastName}`
                  }))}
                placeholder="Seleziona co-formatore"
                isClearable
                classNamePrefix="react-select"
              />
              <div className="text-xs text-gray-500 mt-1">Il co-formatore non può coincidere con il formatore principale.</div>
            </div>
          </div>
        </div>
      )}

      {/* Attendance for Selected Date */}
      {dates[selectedDayIdx] && (
        <div className="border rounded p-4">
          <div className="flex justify-between items-center mb-4">
            <h4 className="font-medium">
              Presenze per {formatDate(dates[selectedDayIdx].date)}
            </h4>
            <div className="space-x-2">
              <Button
                type="button"
                size="sm"
                variant="secondary"
                onClick={() => onSelectAllForDate(selectedDayIdx)}
              >
                Tutti Presenti
              </Button>
              <Button
                type="button"
                size="sm"
                variant="secondary"
                onClick={() => onSelectNoneForDate(selectedDayIdx)}
              >
                Nessuno
              </Button>
            </div>
          </div>

          <div className="border rounded overflow-visible">
            {selectedPersons.length > 0 ? (
              persons
                .filter((person: Person) => selectedPersons.map(String).includes(String(person.id)))
                .map((person: Person) => (
                  <div key={`${selectedDayIdx}-${person.id}`} className="flex items-center p-3 hover:bg-gray-50 border-b last:border-b-0">
                    <input
                      type="checkbox"
                      id={`attendance-${selectedDayIdx}-${person.id}`}
                      checked={(attendance[selectedDayIdx] || []).map(String).includes(String(person.id))}
                      onChange={(e) => onAttendanceChange(selectedDayIdx, person.id, e.target.checked)}
                      className="mr-3 w-4 h-4 accent-blue-600"
                    />
                    <div className="flex-1">
                      <div className="font-medium">
                        {person.firstName} {person.lastName}
                      </div>
                      <div className="text-sm text-gray-500">
                        {person.companyId != null ? getCompanyName(person.companyId) : 'Senza azienda'}
                      </div>
                      {person.email && (
                        <div className="text-xs text-gray-400">{person.email}</div>
                      )}
                    </div>
                  </div>
                ))
            ) : (
              <div className="text-center py-8 text-gray-500">
                Nessun partecipante selezionato
              </div>
            )}
          </div>

          {/* Attendance Summary */}
          <div className="mt-3 text-right text-sm text-gray-600">
            Presenti: <span className="font-medium">{(attendance[selectedDayIdx] || []).length}</span> / {selectedPersons.length}
          </div>
        </div>
      )}
    </div>
  );
};

export default AttendanceManager;

import React, { useEffect } from 'react';
import { Input } from '../../../design-system/atoms/Input';
import { Label } from '../../../design-system/atoms/Label';
import Select from 'react-select';
import AsyncSelect from 'react-select/async';
import { normalizeText as normalizeTextUtil, extractCourses as extractCoursesUtil } from '../utils';
import { apiGet } from '../../../services/api';
import { SelectionPills } from '../../../design-system/molecules/SelectionPills/SelectionPills';
import type { SelectionPillAction } from '../../../design-system/molecules/SelectionPills/SelectionPills';

// Sostituisci i tipi locali con alias ai tipi condivisi per evitare divergenze
type Training = import('../utils').Training;
type Trainer = import('../utils').Trainer;

interface CourseDetailsFormProps {
  trainings: Training[];
  trainers: Trainer[];
  formData: {
    training_id: string | number;
    trainer_id: string | number;
    co_trainer_id: string | number;
    location: string;
    max_participants: number;
    notes: string;
    delivery_mode?: string;
    risk_level?: string;
    course_type?: string;
  };
  onFormDataChange: (field: string, value: unknown) => void;
  selectedCourse: Training | undefined;
  filteredTrainers: Trainer[];
  coTrainerOptions: Trainer[];
  courseSearch: string;
  onCourseSearchChange: (search: string) => void;
  DELIVERY_MODES: Array<{ value: string; label: string }>;
  RISK_LEVEL_OPTIONS?: Array<{ value: string; label: string }>;
  COURSE_TYPE_OPTIONS?: Array<{ value: string; label: string }>;
  onCourseSelected?: (course: Training | undefined) => void;
}

interface CourseOption {
  value: string;
  label: string;
}

interface GroupedCourseOption {
  label: string;
  options: CourseOption[];
}

export const CourseDetailsForm: React.FC<CourseDetailsFormProps> = ({
  trainings = [],
  formData,
  onFormDataChange,
  selectedCourse,
  filteredTrainers,
  courseSearch,
  onCourseSearchChange,
  DELIVERY_MODES,
  RISK_LEVEL_OPTIONS,
  COURSE_TYPE_OPTIONS,
  onCourseSelected
}) => {

  // Build unique course options by macro-corso (unique title/name)
  const uniqueCourseOptions = React.useMemo(() => {
    const titles = new Set<string>();
    trainings.forEach((t: Training) => {
      const title = t.title || t.name || `Corso ${t.id}`;
      titles.add(title);
    });
    return Array.from(titles)
      .sort((a, b) => a.localeCompare(b))
      .map(title => ({ value: title, label: title }));
  }, [trainings]);

  // Evita clipping del menu dentro il modal e prefetch iniziale se non ho corsi locali
  const menuPortalTarget = typeof window !== 'undefined' ? document.body : undefined;
  // Se ho poche opzioni locali, lascia che AsyncSelect faccia prefetch dal server
  const defaultCourseOptions = uniqueCourseOptions.length >= 10 ? uniqueCourseOptions : true;
  const selectedCourseOption =
    selectedCourse
      ? { value: selectedCourse.title || selectedCourse.name, label: selectedCourse.title || selectedCourse.name }
      : null;

  const riskValue = selectedCourse?.riskLevel || (formData.risk_level as string) || '';
  const courseTypeValue = selectedCourse?.courseType || (formData.course_type as string) || '';

  // AUTOSELEZIONE: se esiste una sola opzione valida e nessun valore impostato, seleziona automaticamente
  useEffect(() => {
    if (!riskValue && RISK_LEVEL_OPTIONS && RISK_LEVEL_OPTIONS.length === 1) {
      onFormDataChange('risk_level', RISK_LEVEL_OPTIONS[0].value);
    }
  }, [riskValue, RISK_LEVEL_OPTIONS, onFormDataChange]);

  useEffect(() => {
    if (!courseTypeValue && COURSE_TYPE_OPTIONS && COURSE_TYPE_OPTIONS.length === 1) {
      onFormDataChange('course_type', COURSE_TYPE_OPTIONS[0].value);
    }
  }, [courseTypeValue, COURSE_TYPE_OPTIONS, onFormDataChange]);

  interface SelectStylesBase {
    [key: string]: unknown;
  }

  const selectStyles = {
    control: (base: SelectStylesBase) => ({
      ...base,
      borderRadius: 9999,
      minHeight: 40
    }),
    valueContainer: (base: SelectStylesBase) => ({ ...base, paddingLeft: 14, paddingRight: 14 }),
    indicatorsContainer: (base: SelectStylesBase) => ({ ...base, paddingRight: 8 })
  } as const;

  const extractCourses = extractCoursesUtil;

  const normalizeText = normalizeTextUtil;

  const loadCourseOptions = async (inputValue: string) => {
    try {
      const termRaw = inputValue || '';
      const term = encodeURIComponent(termRaw);

      let items: Training[] = [];

      // Timeout aumentato a 15 secondi per gestire il RequestThrottler
      const timeoutPromise = new Promise<never>((_, reject) => {
        setTimeout(() => reject(new Error('Request timeout')), 15000);
      });

      // Helper: tenta fetch autenticato di TUTTI i corsi (privati), con fallback ai pubblici
      const fetchAllPrivateCourses = async (): Promise<Training[]> => {
        try {
          // Nessun filtro lato server: affidiamoci alla cache del client e filtriamo localmente
          const apiCall = apiGet(`/api/courses`);
          const res = await Promise.race([apiCall, timeoutPromise]);
          return extractCourses(res);
        } catch (e: any) {
          // 401/403 → utente non autenticato o permessi insufficienti: fallback ai pubblici
          if (e?.response?.status === 401 || e?.response?.status === 403) {
            try {
              const pubRes = await Promise.race([
                apiGet(`/api/public/courses?limit=200`),
                timeoutPromise
              ]);
              return extractCourses(pubRes);
            } catch (pubErr) {
              console.warn('Public courses fallback failed:', pubErr);
              return [] as Training[];
            }
          }
          // Altri errori → ritorna array vuoto, gestito dai fallback successivi
          console.warn('Private courses fetch failed:', e);
          return [] as Training[];
        }
      };

      // 1) Se non c'è input, carica da props se disponibili, altrimenti preleva tutti i corsi (privati) con fallback ai pubblici
      if (!termRaw) {
        const privateAll = await fetchAllPrivateCourses();
        if (trainings && trainings.length > 0) {
          const map = new Map<string, Training>();
          const pushUnique = (arr: Training[]) => {
            arr.forEach((c) => {
              const rawTitle = (c?.title || c?.name || `Corso ${c?.id}`) as string;
              const key = normalizeText(rawTitle);
              if (!map.has(key)) map.set(key, c);
            });
          };
          pushUnique(trainings);
          pushUnique(privateAll);
          items = Array.from(map.values()).slice(0, 200);
        } else {
          items = privateAll;
        }
      } else {
        // 2) Con input, prova prima il filtro locale poi, se necessario, carica tutti i corsi e filtra client-side; in ultimo usa la ricerca pubblica
        if (trainings && trainings.length > 0) {
          const localFiltered = trainings.filter((c: Training) => {
            const title = (c?.title || c?.name || '').toLowerCase();
            return title.includes(termRaw.toLowerCase());
          });
          if (localFiltered.length > 0) {
            items = localFiltered.slice(0, 100);
          } else {
            // Carica tutti i corsi (privati) e filtra client-side, con fallback ai pubblici
            const all = await fetchAllPrivateCourses();
            const filtered = all.filter((c: Training) => {
              const title = (c?.title || c?.name || '').toLowerCase();
              return title.includes(termRaw.toLowerCase());
            });
            if (filtered.length > 0) {
              items = filtered.slice(0, 100);
            } else {
              try {
                const apiCall = apiGet(`/api/public/courses?search=${term}&q=${term}&limit=50`);
                const res = await Promise.race([apiCall, timeoutPromise]);
                items = extractCourses(res);
              } catch (apiError) {
                console.warn('API public search failed, using local trainings as fallback:', apiError);
                items = trainings.slice(0, 100);
              }
            }
          }
        } else {
          // Nessun dato locale: carica tutti i corsi (privati), filtra client-side, poi fallback alla ricerca pubblica
          const all = await fetchAllPrivateCourses();
          const filtered = all.filter((c: Training) => {
            const title = (c?.title || c?.name || '').toLowerCase();
            return title.includes(termRaw.toLowerCase());
          });
          if (filtered.length > 0) {
            items = filtered.slice(0, 100);
          } else {
            try {
              const apiCall = apiGet(`/api/public/courses?search=${term}&q=${term}&limit=50`);
              const res = await Promise.race([apiCall, timeoutPromise]);
              items = extractCourses(res);
            } catch (apiError) {
              console.warn('API public search failed, no fallback available:', apiError);
              items = [];
            }
          }
        }
      }

      // 3) Raggruppa per macro-corso (titolo) e restituisci opzioni uniche
      const groupedByTitle = new Map<string, { value: string; label: string }>();
      items.forEach((c: Training) => {
        const rawTitle = (c?.title || c?.name || `Corso ${c?.id}`) as string;
        const key = normalizeText(rawTitle);
        if (!groupedByTitle.has(key)) {
          groupedByTitle.set(key, { value: rawTitle, label: rawTitle });
        }
      });
      return Array.from(groupedByTitle.values()).sort((a, b) => a.label.localeCompare(b.label));
    } catch (err: unknown) {
      const errorMessage = err instanceof Error ? err.message : String(err);
      console.warn('Errore durante la ricerca corsi:', errorMessage);

      // Fallback migliorato: usa sempre i trainings passati come props
      if (trainings && trainings.length > 0) {
        const groupedByTitle = new Map<string, { value: string; label: string }>();
        trainings.forEach((c: Training) => {
          const rawTitle = (c?.title || c?.name || `Corso ${c?.id}`) as string;
          const key = normalizeText(rawTitle);
          if (!groupedByTitle.has(key) && (!inputValue || rawTitle.toLowerCase().includes(inputValue.toLowerCase()))) {
            groupedByTitle.set(key, { value: rawTitle, label: rawTitle });
          }
        });
        return Array.from(groupedByTitle.values()).sort((a, b) => a.label.localeCompare(b.label));
      }

      return [];
    }
  };

//Azioni per le pillole di rischio e tipo
const riskActions: SelectionPillAction[] = (RISK_LEVEL_OPTIONS || []).map(opt => ({
  label: opt.label,
  onClick: () => onFormDataChange('risk_level', opt.value === riskValue ? '' : opt.value),
  variant: (opt.value === riskValue ? 'primary' : 'secondary') as 'primary' | 'secondary'
}));

const typeActions: SelectionPillAction[] = (COURSE_TYPE_OPTIONS || []).map(opt => ({
  label: opt.label,
  onClick: () => onFormDataChange('course_type', opt.value === courseTypeValue ? '' : opt.value),
  variant: (opt.value === courseTypeValue ? 'primary' : 'secondary') as 'primary' | 'secondary'
}));

// Fix: I campi devono essere abilitati quando c'è un corso selezionato E ci sono opzioni disponibili
// Non disabilitare se le opzioni sono vuote, ma solo se non c'è un corso selezionato
const riskDisabled = !selectedCourse;
const typeDisabled = !selectedCourse;

return (
  <div className="space-y-4">
    <h3 className="font-semibold text-gray-700">Dettagli del Corso</h3>

    {/* Course Selection - unique options by macro-corso */}
    <div>
      <Label>Corso *</Label>
      <AsyncSelect
        cacheOptions
        defaultOptions={defaultCourseOptions}
        loadOptions={loadCourseOptions}
        value={selectedCourseOption}
        onChange={async (option) => {
          if (!option) {
            onFormDataChange('training_id', '');
            onFormDataChange('risk_level', '');
            onFormDataChange('course_type', '');
            onCourseSelected?.(undefined);
            onCourseSearchChange('');
            return;
          }
          const macroTitle = (option as { value: string; label: string }).value as string;
          onFormDataChange('training_id', '');
          onFormDataChange('risk_level', '');
          onFormDataChange('course_type', '');
          onCourseSelected?.({ id: '', title: macroTitle } as Training);
          onCourseSearchChange('');
        }}
        noOptionsMessage={() => courseSearch ? 'Nessun corso trovato: prova con parole chiave diverse' : 'Inizia a digitare per cercare'}
        placeholder="Seleziona un corso"
        isClearable
        classNamePrefix="react-select"
        styles={{
          ...selectStyles,
          menuPortal: (base: SelectStylesBase) => ({ ...base, zIndex: 9999 })
        }}
        menuPortalTarget={menuPortalTarget}
        inputValue={courseSearch}
        onInputChange={(value, meta) => {
          if (meta.action === 'input-change') onCourseSearchChange(value);
        }}
      />

      {selectedCourse && ((
          (selectedCourse.duration ||
            ((Array.isArray(selectedCourse?.certifications)
              ? selectedCourse!.certifications
              : (typeof selectedCourse?.certifications === 'string'
                ? (selectedCourse!.certifications as unknown as string).split(',').map((c: string) => c.trim()).filter(Boolean)
                : [] as string[])
            ).length > 0) ||
            selectedCourse.riskLevel ||
            selectedCourse.courseType)
        ) && (
        <div className="mt-2 p-3 bg-blue-50 rounded border">
          <div className="text-sm">
            {/* Rimosso: nome corso duplicato */}
            {selectedCourse.duration && (
              <div className="text-gray-600">Durata: {selectedCourse.duration} ore</div>
            )}
            {(
              (Array.isArray(selectedCourse?.certifications)
                ? selectedCourse!.certifications
                : (typeof selectedCourse?.certifications === 'string'
                  ? (selectedCourse!.certifications as unknown as string).split(',').map((c: string) => c.trim()).filter(Boolean)
                  : [] as string[])
              ).length > 0
            ) && (
              <div className="text-gray-600">
                Certificazioni richieste: {
                  (Array.isArray(selectedCourse?.certifications)
                    ? selectedCourse!.certifications
                    : (typeof selectedCourse?.certifications === 'string'
                      ? (selectedCourse!.certifications as unknown as string).split(',').map((c: string) => c.trim()).filter(Boolean)
                      : [] as string[])
                  ).join(', ')
                }
              </div>
            )}
            {(selectedCourse.riskLevel || selectedCourse.courseType) && (
              <div className="text-gray-600">
                {selectedCourse.riskLevel && (
                  <span className="mr-4">Rischio: {selectedCourse.riskLevel}</span>
                )}
                {selectedCourse.courseType && (
                  <span>Tipo: {selectedCourse.courseType === 'PRIMO_CORSO' ? 'Primo corso' : 'Aggiornamento'}</span>
                )}
              </div>
            )}
          </div>
        </div>
        )
      )}

      {/* Risk Level + Course Type side-by-side */}
      <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
        <div>
          <Label>Livello di Rischio *</Label>
          {riskDisabled ? (
            <div className="text-sm text-gray-500 py-2">Non selezionabile</div>
          ) : (
            <SelectionPills actions={riskActions} className="mt-1" />
          )}
          {selectedCourse?.riskLevel && (
            <div className="text-xs text-gray-500 mt-1">Rischio suggerito: {selectedCourse.riskLevel}</div>
          )}
        </div>

        <div>
          <Label>Tipo Corso *</Label>
          {typeDisabled ? (
            <div className="text-sm text-gray-500 py-2">Non selezionabile</div>
          ) : (
            <SelectionPills actions={typeActions} className="mt-1" />
          )}
          {selectedCourse?.courseType && (
