            </div>

            {/* Main Trainer */}
            <div>
              <Label>Formatore Principale</Label>
              <Select<OptionType>
                value={filteredTrainers.find(t => String(t.id) === String(dateEntry.trainerId)) ? {
                  value: String(dateEntry.trainerId),
