  showProgress?: boolean;
  size?: 'sm' | 'md' | 'lg';
  overlay?: boolean;
}

// Configurazioni per ogni tipo di loading
const LOADING_CONFIGS: Record<LoadingType, {
  icon: React.ComponentType<{ className?: string }>;
  defaultMessage: string;
  color: string;
  duration?: string;
}> = {
