    defaultMessage: 'Caricamento dati...',
    color: 'text-blue-500',
    duration: '2-3 secondi'
  },
  'save': {
    icon: Loader2,
    defaultMessage: 'Salvataggio in corso...',
    color: 'text-green-500',
    duration: '3-5 secondi'
  },
  'step-transition': {
