    certifications?: string[] | string;
  };
}

export const TrainerSelector: React.FC<TrainerSelectorProps> = ({
  trainers,
  filteredTrainers,
  coTrainerOptions,
  formData,
  onFormDataChange,
  selectedCourse
}) => {
  const getTrainerName = (trainerId: string | number) => {
    const trainer = trainers.find(t => String(t.id) === String(trainerId));
    return trainer ? `${trainer.firstName} ${trainer.lastName}` : '';
  };

  const normalizeText = normalizeTextUtil;

  const normalizeCerts = normalizeCertList;

  const isTrainerQualified = (trainer: Trainer) => {
    const required = normalizeCerts(selectedCourse?.certifications);
    if (required.length === 0) return true;
    const trainerCerts = normalizeCerts(trainer.certifications);
    // Matching tollerante: normalizzo e confronto per substring in entrambe le direzioni
    const reqNorm = required.map(c => normalizeText(c));
    const trainerNorm = trainerCerts.map(c => normalizeText(c));
    return reqNorm.every(req => trainerNorm.some(tc => tc.includes(req) || req.includes(tc)));
  };

  const selectedTrainer = trainers.find(t => String(t.id) === String(formData.trainer_id));
  const selectedCoTrainer = trainers.find(t => String(t.id) === String(formData.co_trainer_id));

  return (
    <div className="space-y-4">
      <h3 className="font-semibold text-gray-700">Formatori</h3>

      {/* Main Trainer */}
      <div>
        <Label>Formatore Principale *</Label>
        <Select
          value={selectedTrainer ? {
            value: selectedTrainer.id,
            label: `${selectedTrainer.firstName} ${selectedTrainer.lastName}`
          } : null}
          onChange={(option) => {
            onFormDataChange('trainer_id', option ? option.value : '');
          }}
          options={filteredTrainers.map(t => ({
            value: t.id,
            label: `${t.firstName} ${t.lastName}`,
            isDisabled: !isTrainerQualified(t)
          }))}
          placeholder="Seleziona formatore principale"
          isClearable
          isSearchable
          formatOptionLabel={(option: { value: string | number; label: string }) => (
            <div className="flex justify-between items-center">
              <span className={!isTrainerQualified(trainers.find(t => String(t.id) === String(option.value))!) ? 'text-gray-400' : ''}>
                {option.label}
              </span>
              {!isTrainerQualified(trainers.find(t => String(t.id) === String(option.value))!) && (
                <span className="text-xs text-red-500">Non qualificato</span>
              )}
            </div>
          )}
        />

        {selectedTrainer && (
          <div className="mt-2 p-3 bg-blue-50 rounded border">
            <div className="text-sm">
              <div className="font-medium">{selectedTrainer.firstName} {selectedTrainer.lastName}</div>
              {normalizeCerts(selectedTrainer.certifications).length > 0 && (
                <div className="text-gray-600">
                  Certificazioni: {normalizeCerts(selectedTrainer.certifications).join(', ')}
                </div>
              )}
              {normalizeCerts(selectedCourse?.certifications).length > 0 && (
                <div className={`text-xs mt-1 ${isTrainerQualified(selectedTrainer) ? 'text-green-600' : 'text-red-600'}`}>
                  {isTrainerQualified(selectedTrainer) 
                    ? '✓ Qualificato per questo corso' 
                    : '⚠ Non ha le certificazioni richieste'}
                </div>
              )}
            </div>
          </div>
        )}
      </div>

      {/* Co-Trainer */}
      <div>
        <Label>Co-Formatore (Opzionale)</Label>
        <Select
          value={selectedCoTrainer ? {
            value: selectedCoTrainer.id,
            label: `${selectedCoTrainer.firstName} ${selectedCoTrainer.lastName}`
          } : null}
          onChange={(option) => {
            onFormDataChange('co_trainer_id', option ? option.value : '');
          }}
          options={coTrainerOptions.map(t => ({
            value: t.id,
            label: `${t.firstName} ${t.lastName}`,
            isDisabled: !isTrainerQualified(t)
          }))}
          placeholder="Seleziona co-formatore"
          isClearable
          isSearchable
          formatOptionLabel={(option: { value: string | number; label: string }) => (
            <div className="flex justify-between items-center">
              <span className={!isTrainerQualified(trainers.find(t => String(t.id) === String(option.value))!) ? 'text-gray-400' : ''}>
                {option.label}
              </span>
              {!isTrainerQualified(trainers.find(t => String(t.id) === String(option.value))!) && (
                <span className="text-xs text-red-500">Non qualificato</span>
              )}
            </div>
          )}
        />

        {selectedCoTrainer && (
          <div className="mt-2 p-3 bg-green-50 rounded border">
            <div className="text-sm">
              <div className="font-medium">{selectedCoTrainer.firstName} {selectedCoTrainer.lastName}</div>
              {normalizeCerts(selectedCoTrainer.certifications).length > 0 && (
                <div className="text-gray-600">
                  Certificazioni: {normalizeCerts(selectedCoTrainer.certifications).join(', ')}
                </div>
              )}
              {normalizeCerts(selectedCourse?.certifications).length > 0 && (
                <div className={`text-xs mt-1 ${isTrainerQualified(selectedCoTrainer) ? 'text-green-600' : 'text-red-600'}`}>
                  {isTrainerQualified(selectedCoTrainer) 
                    ? '✓ Qualificato per questo corso' 
                    : '⚠ Non ha le certificazioni richieste'}
                </div>
              )}
            </div>
          </div>
        )}
      </div>

      {/* Trainer Requirements Info */}
      {normalizeCerts(selectedCourse?.certifications).length > 0 && (
        <div className="bg-yellow-50 p-3 rounded border">
          <div className="text-sm">
            <div className="font-medium text-yellow-800 mb-1">
