import React from 'react';
import { Label } from '../../../../design-system/atoms/Label';
import { Input } from '../../../../design-system/atoms/Input';
import { Button } from '../../../../design-system/atoms/Button';
import type { Person, Company } from '../../../../types';

interface StepAttendanceSimpleProps {
  persons: Person[];
  selectedPersons: Set<string | number>;
  selectedCompanies: Set<string | number>;
  attendance: Record<number, (string | number)[]>;
  personSearch: string;
  personTab: string | number;
  onPersonToggle: (personId: string | number) => void;
  onSelectAllPersons: (personIds: (string | number)[]) => void;
  onDeselectAllPersons: () => void;
  onAttendanceChange: (dateIdx: number, personIds: (string | number)[]) => void;
  onPersonSearchChange: (search: string) => void;
  onPersonTabChange: (tab: string | number) => void;
}

export const StepAttendanceSimple: React.FC<StepAttendanceSimpleProps> = ({
  persons,
  selectedPersons,
  selectedCompanies,
  attendance,
  personSearch,
  personTab,
  onPersonToggle,
  onSelectAllPersons,
  onDeselectAllPersons,
  onAttendanceChange,
  onPersonSearchChange,
  onPersonTabChange
}) => {
  // Filtra le persone in base alle aziende selezionate e alla ricerca
  const filteredPersons = persons.filter(person => {
    // Se non ci sono aziende selezionate, mostra tutte le persone
    if (selectedCompanies.size === 0) return true;

    // Filtra per azienda selezionata
    const matchesCompany = person.company_id && selectedCompanies.has(person.company_id);

    // Filtra per ricerca
    const matchesSearch = !personSearch || 
      person.name?.toLowerCase().includes(personSearch.toLowerCase()) ||
      person.surname?.toLowerCase().includes(personSearch.toLowerCase()) ||
      person.email?.toLowerCase().includes(personSearch.toLowerCase());

    return matchesCompany && matchesSearch;
  });

  const handleSelectAll = () => {
    const personIds = filteredPersons.map(p => p.id);
    onSelectAllPersons(personIds);
  };

  const handleDeselectAll = () => {
    onDeselectAllPersons();
  };

  return (
    <div className="space-y-6">
      {/* Header con statistiche */}
      <div className="bg-blue-50 border border-blue-200 rounded-lg p-4">
        <div className="grid grid-cols-2 md:grid-cols-4 gap-4 text-sm">
          <div>
            <span className="font-medium text-blue-900">Aziende:</span>
            <span className="ml-1 text-blue-700">{selectedCompanies.size}</span>
          </div>
          <div>
            <span className="font-medium text-blue-900">Persone Disponibili:</span>
            <span className="ml-1 text-blue-700">{filteredPersons.length}</span>
          </div>
          <div>
            <span className="font-medium text-blue-900">Selezionate:</span>
            <span className="ml-1 text-blue-700">{selectedPersons.size}</span>
          </div>
          <div>
            <span className="font-medium text-blue-900">Presenze:</span>
            <span className="ml-1 text-blue-700">{Object.keys(attendance).length}</span>
          </div>
        </div>
      </div>

      {/* Controlli */}
      <div className="flex flex-col sm:flex-row gap-4">
        <div className="flex-1">
          <Label htmlFor="personSearch">Cerca Persona</Label>
          <Input
            id="personSearch"
            type="text"
            value={personSearch}
            onChange={(e) => onPersonSearchChange(e.target.value)}
            placeholder="Cerca per nome, cognome o email..."
          />
        </div>
        <div className="flex gap-2 items-end">
          <Button
            variant="outline"
            onClick={handleSelectAll}
            disabled={filteredPersons.length === 0}
          >
            Seleziona Tutti
          </Button>
          <Button
            variant="outline"
            onClick={handleDeselectAll}
            disabled={selectedPersons.size === 0}
          >
            Deseleziona Tutti
          </Button>
        </div>
      </div>

      {/* Lista persone */}
      <div className="space-y-2">
        <Label>Partecipanti</Label>
        <div className="max-h-96 overflow-y-auto border border-gray-200 rounded-lg">
          {filteredPersons.length === 0 ? (
            <div className="p-4 text-center text-gray-500">
              {selectedCompanies.size === 0 
                ? 'Seleziona prima almeno un\'azienda nel passo precedente'
                : personSearch 
                  ? 'Nessuna persona trovata con i criteri di ricerca'
                  : 'Nessuna persona disponibile per le aziende selezionate'
              }
            </div>
          ) : (
            <div className="divide-y divide-gray-200">
              {filteredPersons.map((person) => {
                const isSelected = selectedPersons.has(person.id);
                return (
                  <div
                    key={person.id}
                    className={`p-4 flex items-center justify-between hover:bg-gray-50 cursor-pointer ${
                      isSelected ? 'bg-green-50 border-l-4 border-l-green-500' : ''
                    }`}
                    onClick={() => onPersonToggle(person.id)}
                  >
                    <div className="flex-1">
                      <div className="font-medium text-gray-900">
                        {person.name} {person.surname}
                      </div>
                      {person.email && (
                        <div className="text-sm text-gray-500">{person.email}</div>
                      )}
                      {person.phone && (
                        <div className="text-sm text-gray-500">{person.phone}</div>
                      )}
                      {person.role && (
                        <div className="text-xs text-blue-600 bg-blue-100 px-2 py-1 rounded-full inline-block mt-1">
                          {person.role}
                        </div>
                      )}
                    </div>
                    <div className="ml-4">
                      <input
                        type="checkbox"
                        checked={isSelected}
                        onChange={() => onPersonToggle(person.id)}
                        className="h-4 w-4 text-green-600 focus:ring-green-500 border-gray-300 rounded"
                      />
                    </div>
                  </div>
                );
              })}
            </div>
          )}
        </div>
      </div>

      {/* Riepilogo selezioni */}
      {selectedPersons.size > 0 && (
        <div className="bg-green-50 border border-green-200 rounded-lg p-4">
          <div className="text-green-800 font-medium mb-2">
            {selectedPersons.size} partecipante{selectedPersons.size !== 1 ? 'i' : ''} selezionato{selectedPersons.size !== 1 ? 'i' : ''}
          </div>
          <div className="text-green-700 text-sm">
            Le presenze verranno gestite automaticamente per tutte le date del corso.
            Potrai modificare le presenze specifiche per ogni giornata nel passo successivo.
          </div>
        </div>
      )}

      {/* Avviso se nessuna azienda selezionata */}
      {selectedCompanies.size === 0 && (
        <div className="bg-yellow-50 border border-yellow-200 rounded-lg p-4">
          <div className="text-yellow-800 font-medium mb-2">
            ⚠️ Nessuna azienda selezionata
          </div>
          <div className="text-yellow-700 text-sm">
            Torna al passo precedente per selezionare almeno un'azienda prima di scegliere i partecipanti.
          </div>
        </div>
      )}
    </div>
  );
};

