import React, { useMemo } from 'react';
import { CompanyEmployeeSelector } from '../index';
import { Label } from '../../../../design-system/atoms/Label';
import type { FormData } from '../../hooks/useFormData';

// Simplified props interface with consolidated objects
interface StepCompanySelectionOptimizedProps {
  // Selection state (consolidated)
  selections: {
    persons: (string | number)[];
    companies: (string | number)[];
    onCompanyToggle: (companyId: string | number) => void;
    onPersonToggle: (personId: string | number) => void;
    onSelectAllPersons: (companyId: string | number) => void;
    onDeselectAllPersons: (companyId: string | number) => void;
  };

  // Search state (consolidated)
  search: {
    company: string;
    setCompany: (value: string) => void;
    person: string;
    setPerson: (value: string) => void;
  };

  // Tab state
  tab: {
    current: string | number;
    onChange: (tab: string | number) => void;
  };

  // Data sources
  data: {
    companies: any[];
    persons: any[];
  };

  // Utility functions (consolidated)
  utils: {
    getPersonIdsForCompany: (companyId: string) => (string | number)[];
    getCompanyName: (companyId: string | number) => string;
  };
}

export const StepCompanySelectionOptimized: React.FC<StepCompanySelectionOptimizedProps> = ({
  selections,
  search,
  tab,
  data,
  utils
}) => {
  // Memoize filtered companies for performance
  const filteredCompanies = useMemo(() => {
    if (!search.company.trim()) return data.companies;

    const searchTerm = search.company.toLowerCase();
    return data.companies.filter(company => 
      company.name?.toLowerCase().includes(searchTerm) ||
      company.description?.toLowerCase().includes(searchTerm) ||
      company.code?.toLowerCase().includes(searchTerm)
    );
  }, [data.companies, search.company]);

  // Memoize filtered persons for performance
  const filteredPersons = useMemo(() => {
    if (!search.person.trim()) return data.persons;

    const searchTerm = search.person.toLowerCase();
    return data.persons.filter(person => 
      person.name?.toLowerCase().includes(searchTerm) ||
      person.surname?.toLowerCase().includes(searchTerm) ||
      person.email?.toLowerCase().includes(searchTerm) ||
      `${person.name} ${person.surname}`.toLowerCase().includes(searchTerm)
    );
  }, [data.persons, search.person]);

  // Memoize selection statistics
  const selectionStats = useMemo(() => {
    const totalCompanies = filteredCompanies.length;
    const selectedCompaniesCount = selections.companies.length;
    const totalPersons = filteredPersons.length;
    const selectedPersonsCount = selections.persons.length;

    return {
      companies: {
        total: totalCompanies,
        selected: selectedCompaniesCount,
        percentage: totalCompanies > 0 ? Math.round((selectedCompaniesCount / totalCompanies) * 100) : 0
      },
      persons: {
        total: totalPersons,
        selected: selectedPersonsCount,
        percentage: totalPersons > 0 ? Math.round((selectedPersonsCount / totalPersons) * 100) : 0
      }
    };
  }, [filteredCompanies.length, selections.companies.length, filteredPersons.length, selections.persons.length]);

  // Enhanced company toggle with batch operations
  const handleCompanyToggle = (companyId: string | number) => {
    selections.onCompanyToggle(companyId);

    // Auto-select/deselect all persons in company if company is selected/deselected
    const isCompanySelected = selections.companies.includes(companyId);
    if (isCompanySelected) {
      selections.onSelectAllPersons(companyId);
    } else {
      selections.onDeselectAllPersons(companyId);
    }
  };

  return (
    <div className="space-y-6">
      {/* Selection Statistics */}
      <div className="bg-blue-50 p-4 rounded-lg border border-blue-200">
        <Label className="text-lg font-semibold mb-3 block text-blue-800">
          Selezione Aziende e Dipendenti
        </Label>

        <div className="grid grid-cols-2 gap-4 text-sm">
          <div className="bg-white p-3 rounded border">
            <div className="font-medium text-gray-700">Aziende</div>
            <div className="text-lg font-bold text-blue-600">
              {selectionStats.companies.selected} / {selectionStats.companies.total}
            </div>
            <div className="text-xs text-gray-500">
              {selectionStats.companies.percentage}% selezionate
            </div>
          </div>

          <div className="bg-white p-3 rounded border">
            <div className="font-medium text-gray-700">Dipendenti</div>
            <div className="text-lg font-bold text-green-600">
              {selectionStats.persons.selected} / {selectionStats.persons.total}
            </div>
            <div className="text-xs text-gray-500">
              {selectionStats.persons.percentage}% selezionati
            </div>
          </div>
        </div>
      </div>

      {/* Company Employee Selector */}
      <div className="bg-white p-6 rounded-lg shadow-sm border">
        <CompanyEmployeeSelector
          selectedPersons={selections.persons}
          selectedCompanies={selections.companies}
          onCompanyToggle={handleCompanyToggle}
          onPersonToggle={selections.onPersonToggle}
          onSelectAllPersons={selections.onSelectAllPersons}
          onDeselectAllPersons={selections.onDeselectAllPersons}
          companySearch={search.company}
          onCompanySearchChange={search.setCompany}
          personSearch={search.person}
          onPersonSearchChange={search.setPerson}
          personTab={tab.current}
          onPersonTabChange={tab.onChange}
          companies={filteredCompanies}
          persons={filteredPersons}
          getPersonIdsForCompany={utils.getPersonIdsForCompany}
          getCompanyName={utils.getCompanyName}
        />
      </div>

      {/* Quick Actions */}
      {(selections.companies.length > 0 || selections.persons.length > 0) && (
        <div className="bg-gray-50 p-4 rounded-lg border">
          <Label className="font-medium text-gray-700 mb-2 block">
            Azioni Rapide
          </Label>

          <div className="flex flex-wrap gap-2">
            <button
              onClick={() => {
                // Clear all selections
                selections.companies.forEach(companyId => {
                  selections.onCompanyToggle(companyId);
                });
                selections.persons.forEach(personId => {
                  selections.onPersonToggle(personId);
                });
              }}
              className="px-3 py-1 text-sm bg-red-100 text-red-700 rounded hover:bg-red-200 transition-colors"
            >
              Deseleziona Tutto
            </button>

            {filteredCompanies.length > 0 && (
              <button
                onClick={() => {
                  filteredCompanies.forEach(company => {
                    if (!selections.companies.includes(company.id)) {
                      handleCompanyToggle(company.id);
                    }
                  });
                }}
                className="px-3 py-1 text-sm bg-blue-100 text-blue-700 rounded hover:bg-blue-200 transition-colors"
              >
                Seleziona Tutte le Aziende
              </button>
            )}
          </div>
        </div>
      )}
    </div>
  );
};

export default StepCompanySelectionOptimized;

