import React, { useMemo } from 'react';
import { Label } from '../../../../design-system/atoms/Label';
import { CourseDetailsForm, DateTimeManager } from '../index';
import type { Training } from '../../types';
import type { FormData } from '../../hooks/useFormData';

// Simplified props interface - only essential data
interface StepCourseDetailsOptimizedProps {
  // Core form data
  formData: FormData;
  onFormDataChange: (field: string, value: unknown) => void;
  setFormData: React.Dispatch<React.SetStateAction<FormData>>;

  // Course selection
  trainings: Training[];
  selectedCourse?: Training;
  onCourseSelect: (course: Training | undefined) => void;

  // Trainers (consolidated)
  trainers: {
    effective: any[];
    filtered: any[];
    coTrainers: any[];
  };

  // Dynamic options (consolidated)
  options: {
    risk: Array<{ value: string; label: string }>;
    courseType: Array<{ value: string; label: string }>;
    deliveryMode: Array<{ value: string; label: string }>;
  };

  // Search state
  search: {
    course: string;
    setCourse: (value: string) => void;
  };

  // Date handlers (consolidated)
  dateHandlers: {
    onChange: (index: number, field: 'date' | 'start' | 'end' | 'trainerId' | 'coTrainerId', value: string) => void;
    onAdd: () => void;
    onRemove: (index: number) => void;
  };

  // Computed values (consolidated)
  computed: {
    totalHours: number;
    courseDuration: number;
    hoursLeft: number;
    formatDate: (isoDate: string) => string;
  };
}

export const StepCourseDetailsOptimized: React.FC<StepCourseDetailsOptimizedProps> = ({
  formData,
  onFormDataChange,
  setFormData,
  trainings = [],
  selectedCourse,
  onCourseSelect,
  trainers,
  options,
  search,
  dateHandlers,
  computed
}) => {
  // Memoize filtered trainings for performance
  const filteredTrainings = useMemo(() => {
    if (!search.course.trim()) return trainings;

    const searchTerm = search.course.toLowerCase();
    return trainings.filter(training => 
      training.name?.toLowerCase().includes(searchTerm) ||
      training.description?.toLowerCase().includes(searchTerm)
    );
  }, [trainings, search.course]);

  // Memoize course options for select
  const courseOptions = useMemo(() => 
    filteredTrainings.map(training => ({
      value: training.id,
      label: training.name || 'Corso senza nome'
    })),
    [filteredTrainings]
  );

  // Handle course selection with validation
  const handleCourseSelection = (courseId: string) => {
    const course = trainings.find(t => t.id === courseId);
    onCourseSelect(course);

    // Auto-fill form data from selected course
    if (course) {
      const updates: Partial<FormData> = {};

      if (course.duration && !formData.training_id) {
        // Auto-set training duration if available
        onFormDataChange('training_id', course.id);
      }
      if (course.riskLevel && !formData.risk_level) {
        updates.risk_level = course.riskLevel;
      }
      if (course.courseType && !formData.course_type) {
        updates.course_type = course.courseType;
      }
      if (course.deliveryMode && !formData.delivery_mode) {
        updates.delivery_mode = course.deliveryMode;
      }

      if (Object.keys(updates).length > 0) {
        setFormData(prev => ({ ...prev, ...updates }));
      }
    }
  };

  return (
    <div className="space-y-6">
      <div className="bg-white p-6 rounded-lg shadow-sm border">
        <Label className="text-lg font-semibold mb-4 block">
          Dettagli del Corso
        </Label>

        <CourseDetailsForm
          formData={formData}
          onFormDataChange={onFormDataChange}
          trainings={filteredTrainings}
          selectedCourse={selectedCourse}
          onCourseSelected={onCourseSelect}
          trainers={trainers.effective}
          filteredTrainers={trainers.filtered}
          coTrainerOptions={trainers.coTrainers}
          courseSearch={search.course}
          onCourseSearchChange={search.setCourse}
          DELIVERY_MODES={options.deliveryMode}
          RISK_LEVEL_OPTIONS={options.risk}
          COURSE_TYPE_OPTIONS={options.courseType}
        />
      </div>

      <div className="bg-white p-6 rounded-lg shadow-sm border">
        <Label className="text-lg font-semibold mb-4 block">
          Programmazione Date e Orari
        </Label>

        <DateTimeManager
          dates={formData.dates}
          trainers={trainers.effective}
          filteredTrainers={trainers.filtered}
          coTrainerOptions={trainers.coTrainers}
          onUpdateDateTime={dateHandlers.onChange}
          onAddDateTime={dateHandlers.onAdd}
          onRemoveDateTime={dateHandlers.onRemove}
          formatDate={computed.formatDate}
          totalSelectedHours={computed.totalHours}
          courseDuration={computed.courseDuration}
          hoursLeft={computed.hoursLeft}
        />

        {/* Hours summary */}
        <div className="mt-4 p-4 bg-blue-50 rounded-lg">
          <div className="grid grid-cols-3 gap-4 text-sm">
            <div>
              <span className="font-medium text-gray-600">Ore Totali:</span>
              <span className="ml-2 font-semibold text-blue-600">
                {computed.totalHours}h
              </span>
            </div>
            <div>
              <span className="font-medium text-gray-600">Durata Corso:</span>
              <span className="ml-2 font-semibold text-green-600">
                {computed.courseDuration}h
              </span>
            </div>
            <div>
              <span className="font-medium text-gray-600">Ore Rimanenti:</span>
              <span className={`ml-2 font-semibold ${
                computed.hoursLeft > 0 ? 'text-orange-600' : 'text-green-600'
              }`}>
                {computed.hoursLeft}h
              </span>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
};

