import React, { useMemo, useCallback } from 'react';
import { DateTimeManager } from '../index';
import { Label } from '../../../../design-system/atoms/Label';
import { Button } from '../../../../design-system/atoms/Button';
import type { FormData } from '../../hooks/useFormData';

// Simplified props interface with consolidated objects
interface StepDateTimeOptimizedProps {
  // Date entries
  dates: FormData['dates'];

  // Trainers (consolidated)
  trainers: {
    effective: any[];
    filtered: any[];
    coTrainers: any[];
  };

  // Date handlers (consolidated)
  handlers: {
    onUpdate: (idx: number, field: 'date' | 'start' | 'end' | 'trainerId' | 'coTrainerId', value: string) => void;
    onAdd: () => void;
    onRemove: (idx: number) => void;
  };

  // Computed values (consolidated)
  computed: {
    totalHours: number;
    courseDuration: number;
    hoursLeft: number;
    formatDate: (isoDate: string) => string;
  };

  // Optional validation
  validation?: {
    minHours?: number;
    maxHours?: number;
    allowOverlap?: boolean;
  };
}

export const StepDateTimeOptimized: React.FC<StepDateTimeOptimizedProps> = ({
  dates = [],
  trainers,
  handlers,
  computed,
  validation = {}
}) => {
  // Memoize date validation
  const dateValidation = useMemo(() => {
    const issues: string[] = [];

    // Check for overlapping dates
    if (!validation.allowOverlap) {
      for (let i = 0; i < dates.length; i++) {
        for (let j = i + 1; j < dates.length; j++) {
          const date1 = dates[i];
          const date2 = dates[j];

          if (date1.date === date2.date) {
            const start1 = new Date(`${date1.date}T${date1.start}`);
            const end1 = new Date(`${date1.date}T${date1.end}`);
            const start2 = new Date(`${date2.date}T${date2.start}`);
            const end2 = new Date(`${date2.date}T${date2.end}`);

            if ((start1 < end2 && end1 > start2)) {
              issues.push(`Sovrapposizione oraria il ${computed.formatDate(date1.date)}`);
            }
          }
        }
      }
    }

    // Check minimum hours
    if (validation.minHours && computed.totalHours < validation.minHours) {
      issues.push(`Ore minime richieste: ${validation.minHours}h (attuali: ${computed.totalHours}h)`);
    }

    // Check maximum hours
    if (validation.maxHours && computed.totalHours > validation.maxHours) {
      issues.push(`Ore massime consentite: ${validation.maxHours}h (attuali: ${computed.totalHours}h)`);
    }

    return {
      isValid: issues.length === 0,
      issues
    };
  }, [dates, computed.totalHours, computed.formatDate, validation]);

  // Enhanced add date with smart defaults
  const handleSmartAddDate = useCallback(() => {
    // If there are existing dates, suggest next working day
    if (dates.length > 0) {
      const lastDate = new Date(dates[dates.length - 1].date);
      const nextDate = new Date(lastDate);

      // Skip to next working day (Monday if last was Friday)
      do {
        nextDate.setDate(nextDate.getDate() + 1);
      } while (nextDate.getDay() === 0 || nextDate.getDay() === 6); // Skip weekends

      // Use same time as last entry
      const lastEntry = dates[dates.length - 1];
      handlers.onAdd();

      // Set smart defaults after adding
      setTimeout(() => {
        const newIndex = dates.length;
        handlers.onUpdate(newIndex, 'date', nextDate.toISOString().split('T')[0]);
        handlers.onUpdate(newIndex, 'start', lastEntry.start);
        handlers.onUpdate(newIndex, 'end', lastEntry.end);
        handlers.onUpdate(newIndex, 'trainerId', String(lastEntry.trainerId));
      }, 0);
    } else {
      handlers.onAdd();
    }
  }, [dates, handlers]);

  // Bulk operations
  const handleBulkTimeUpdate = useCallback((field: 'start' | 'end', value: string) => {
    dates.forEach((_, index) => {
      handlers.onUpdate(index, field, value);
    });
  }, [dates, handlers]);

  const handleBulkTrainerUpdate = useCallback((field: 'trainerId' | 'coTrainerId', value: string) => {
    dates.forEach((_, index) => {
      handlers.onUpdate(index, field, value);
    });
  }, [dates, handlers]);

  return (
    <div className="space-y-6">
      {/* Hours Summary */}
      <div className="bg-white p-6 rounded-lg shadow-sm border">
        <Label className="text-lg font-semibold mb-4 block">
          Programmazione Date e Orari
        </Label>

        <div className="grid grid-cols-3 gap-4 mb-4">
          <div className="bg-blue-50 p-4 rounded-lg text-center">
            <div className="text-2xl font-bold text-blue-600">{computed.totalHours}h</div>
            <div className="text-sm text-gray-600">Ore Totali</div>
          </div>

          <div className="bg-green-50 p-4 rounded-lg text-center">
            <div className="text-2xl font-bold text-green-600">{computed.courseDuration}h</div>
            <div className="text-sm text-gray-600">Durata Corso</div>
          </div>

          <div className={`p-4 rounded-lg text-center ${
            computed.hoursLeft > 0 ? 'bg-orange-50' : 'bg-green-50'
          }`}>
            <div className={`text-2xl font-bold ${
              computed.hoursLeft > 0 ? 'text-orange-600' : 'text-green-600'
            }`}>
              {computed.hoursLeft}h
            </div>
            <div className="text-sm text-gray-600">
              {computed.hoursLeft > 0 ? 'Ore Rimanenti' : 'Completato'}
            </div>
          </div>
        </div>

        {/* Validation Messages */}
        {!dateValidation.isValid && (
          <div className="bg-red-50 border border-red-200 rounded-lg p-4 mb-4">
            <div className="font-medium text-red-800 mb-2">Problemi rilevati:</div>
            <ul className="list-disc list-inside text-sm text-red-700 space-y-1">
              {dateValidation.issues.map((issue, index) => (
                <li key={index}>{issue}</li>
              ))}
            </ul>
          </div>
        )}
      </div>

      {/* Bulk Operations */}
      {dates.length > 1 && (
        <div className="bg-gray-50 p-4 rounded-lg border">
          <Label className="font-medium text-gray-700 mb-3 block">
            Operazioni in Blocco
          </Label>

          <div className="grid grid-cols-2 md:grid-cols-4 gap-3">
            <div>
              <label className="block text-xs text-gray-600 mb-1">Ora Inizio</label>
              <input
                type="time"
                onChange={(e) => handleBulkTimeUpdate('start', e.target.value)}
                className="w-full px-2 py-1 text-sm border rounded"
              />
            </div>

            <div>
              <label className="block text-xs text-gray-600 mb-1">Ora Fine</label>
              <input
                type="time"
                onChange={(e) => handleBulkTimeUpdate('end', e.target.value)}
                className="w-full px-2 py-1 text-sm border rounded"
              />
            </div>

            <div>
              <label className="block text-xs text-gray-600 mb-1">Formatore</label>
              <select
                onChange={(e) => handleBulkTrainerUpdate('trainerId', e.target.value)}
                className="w-full px-2 py-1 text-sm border rounded"
              >
                <option value="">Seleziona...</option>
                {trainers.effective.map(trainer => (
                  <option key={trainer.id} value={trainer.id}>
                    {trainer.name}
                  </option>
                ))}
              </select>
            </div>

            <div>
              <label className="block text-xs text-gray-600 mb-1">Co-Formatore</label>
              <select
                onChange={(e) => handleBulkTrainerUpdate('coTrainerId', e.target.value)}
                className="w-full px-2 py-1 text-sm border rounded"
              >
                <option value="">Nessuno</option>
                {trainers.coTrainers.map(trainer => (
                  <option key={trainer.id} value={trainer.id}>
                    {trainer.name}
                  </option>
                ))}
              </select>
            </div>
          </div>
        </div>
      )}

      {/* Date Time Manager */}
      <div className="bg-white p-6 rounded-lg shadow-sm border">
        <div className="flex justify-between items-center mb-4">
          <Label className="text-lg font-semibold">
            Date del Corso ({dates.length})
          </Label>

          <Button
            onClick={handleSmartAddDate}
            className="bg-blue-600 text-white px-4 py-2 rounded hover:bg-blue-700 transition-colors"
          >
            + Aggiungi Data
          </Button>
        </div>

        <DateTimeManager
          dates={dates}
          trainers={trainers.effective}
          filteredTrainers={trainers.filtered}
          coTrainerOptions={trainers.coTrainers}
          onUpdateDateTime={handlers.onUpdate}
          onAddDateTime={handlers.onAdd}
          onRemoveDateTime={handlers.onRemove}
          formatDate={computed.formatDate}
          totalSelectedHours={computed.totalHours}
          courseDuration={computed.courseDuration}
          hoursLeft={computed.hoursLeft}
        />
      </div>
    </div>
  );
};

export default StepDateTimeOptimized;

