    if (isEditing) {
      const event = existingEvent as Record<string, unknown>;
      const course = event.course as Record<string, unknown> | undefined;
      const dates = (event.dates as Record<string, unknown>[]) || [];

      return {
        training_id: (event.training_id as string) || (course?.id as string) || "",
        trainer_id: "",
        co_trainer_id: "",
        dates: dates.map((d: Record<string, unknown>) => ({
          date: d.date as string,
          start: d.start as string,
          end: d.end as string,
          trainerId: (d.trainer_id || d.trainerId) as string | number,
          coTrainerId: (d.co_trainer_id || d.coTrainerId) as string | number,
        })),
        location: (event.location as string) || "",
        max_participants: (event.max_participants as number) || 20,
        notes: (event.notes as string) || "",
        delivery_mode: (event.delivery_mode as string) || "",
        risk_level: (event.risk_level as string) || (course?.riskLevel as string) || "",
        course_type: (event.course_type as string) || (course?.courseType as string) || "",
      };
    }

    return {
      training_id: "",
      trainer_id: "",
      co_trainer_id: "",
      dates: [{
        date: initialDate || new Date().toISOString().split("T")[0],
        start: initialTime?.start || "09:00",
        end: initialTime?.end || "13:00",
        trainerId: "",
        coTrainerId: "",
      }],
      location: "",
      max_participants: 20,
      notes: "",
      delivery_mode: "",
      risk_level: "",
      course_type: "",
    };
  }, [existingEvent, isEditing, initialDate, initialTime]);

  const [formData, setFormData] = useState<FormData>(initialFormData);

  // Auto-fill risk/course type if defined on course
  useEffect(() => {
    if (!selectedCourse) return;
    setFormData(prev => {
      const updates: Record<string, unknown> = {};
      if (!prev.risk_level && selectedCourse.riskLevel) updates.risk_level = selectedCourse.riskLevel;
      if (!prev.course_type && selectedCourse.courseType) updates.course_type = selectedCourse.courseType;
      return Object.keys(updates).length ? { ...prev, ...updates } : prev;
    });
  }, [selectedCourse]);

  // Auto-select risk/type when only one option is available; clear when none
  useEffect(() => {
    // Risk
    if ((dynamicRiskOptions?.length || 0) === 1 && !formData.risk_level) {
      setFormData(prev => ({ ...prev, risk_level: dynamicRiskOptions[0].value }));
    } else if ((dynamicRiskOptions?.length || 0) === 0 && formData.risk_level) {
      setFormData(prev => ({ ...prev, risk_level: '' }));
    }
    // Course type
    if ((dynamicCourseTypeOptions?.length || 0) === 1 && !formData.course_type) {
      setFormData(prev => ({ ...prev, course_type: dynamicCourseTypeOptions[0].value }));
    } else if ((dynamicCourseTypeOptions?.length || 0) === 0 && formData.course_type) {
      setFormData(prev => ({ ...prev, course_type: '' }));
    }
  }, [dynamicRiskOptions, dynamicCourseTypeOptions, formData.risk_level, formData.course_type]);

  // Computed values
  const timeStringToMinutes = timeStringToMinutesUtil;

  const totalSelectedMinutes = useMemo(() => 
    computeTotalSelectedMinutes(formData.dates, timeStringToMinutes), 
    [formData.dates, timeStringToMinutes]
  );

  const totalSelectedHours = useMemo(() => 
    Math.round((totalSelectedMinutes / 60) * 100) / 100, 
    [totalSelectedMinutes]
  );

  const courseDuration = useMemo(() => {
    const dur = selectedCourse?.duration;
    if (typeof dur === 'number') return dur;
    if (typeof dur === 'string') {
      const parsed = parseFloat(dur.replace(',', '.'));
      return isNaN(parsed) ? 0 : parsed;
    }
    return 0;
  }, [selectedCourse]);

  const hoursLeft = useMemo(() => {
    if (!courseDuration) return 0;
    const left = courseDuration - totalSelectedHours;
    return Math.round(left * 100) / 100;
  }, [courseDuration, totalSelectedHours]);

  // Handlers
  const handleFormDataChange = useCallback((field: string, value: unknown) => {
    setFormData(prev => ({ ...prev, [field]: value }));
  }, []);

  const handleUpdateDateTime = useCallback((idx: number, field: 'date' | 'start' | 'end' | 'trainerId' | 'coTrainerId', value: string) => {
    setFormData(prev => {
      const dates = [...prev.dates];
      const updated = { ...dates[idx], [field]: value };
      dates[idx] = updated;
      return { ...prev, dates };
    });
  }, []);

  const handleAddDateTime = useCallback(() => {
    setFormData(prev => ({
      ...prev,
      dates: [
        ...prev.dates,
        {
          date: new Date().toISOString().split('T')[0],
          start: '09:00',
          end: '13:00',
          trainerId: '',
          coTrainerId: ''
        }
      ]
    }));
  }, []);

  const handleRemoveDateTime = useCallback((idx: number) => {
    setFormData(prev => ({
      ...prev,
      dates: prev.dates.filter((_, i) => i !== idx)
    }));
  }, []);

  // Validation
  const validateAll = useCallback(() => {
    const res = validateScheduleForm(
      {
        training_id: formData.training_id,
        risk_level: formData.risk_level as string,
        course_type: formData.course_type as string,
        location: formData.location as string,
        dates: formData.dates,
      },
      dynamicRiskOptions,
      dynamicCourseTypeOptions,
      timeStringToMinutes,
      courseDuration,
      totalSelectedHours,
    );
    if (!res.valid) {
      setError(res.error);
      return false;
    }
    setError('');
    return true;
  }, [formData, dynamicRiskOptions, dynamicCourseTypeOptions, timeStringToMinutes, courseDuration, totalSelectedHours]);

  return {
    formData,
    setFormData,
    handleFormDataChange,
    handleUpdateDateTime,
    handleAddDateTime,
    handleRemoveDateTime,
    validateAll,
    totalSelectedMinutes,
    totalSelectedHours,
    courseDuration,
    hoursLeft,
    error,
    setError,
  };
}

import { useMemo, useCallback } from 'react';
import type { FormData } from './useFormData';
import type { Training } from '../types';
import { validateScheduleForm } from '../utils';

interface ValidationError {
  field: string;
  message: string;
}

interface ValidationResult {
  isValid: boolean;
  errors: ValidationError[];
  fieldErrors: Record<string, string>;
}

interface UseFormValidationProps {
  formData: FormData;
  dynamicRiskOptions: Array<{ value: string; label: string }>;
  dynamicCourseTypeOptions: Array<{ value: string; label: string }>;
  currentStep: number;
  selectedCourse?: Training;
  courseDuration: number;
  totalSelectedHours: number;
  timeStringToMinutes: (time: string) => number;
  selectedCompanies: Array<string | number>;
  selectedPersons: Array<string | number>;
}

interface UseFormValidationReturn {
  // Validation results
  isValid: boolean;
  errors: ValidationError[];
  fieldErrors: Record<string, string>;

  // Step-specific validation
  isStep0Valid: boolean;
  isStep1Valid: boolean;
  isStep2Valid: boolean;
  isStep3Valid: boolean;
  isStep4Valid: boolean;

  // Validation functions
  validateCurrentStep: () => ValidationResult;
  validateAllSteps: () => ValidationResult;
  validateField: (field: string, value: unknown) => ValidationError | null;
  clearErrors: () => void;
}

/**
 * Hook centralizzato per la gestione della validazione del form
 * Consolida tutta la logica di validazione precedentemente dispersa
 */
export function useFormValidation({
  formData,
  dynamicRiskOptions = [],
  dynamicCourseTypeOptions = [],
  currentStep,
  selectedCourse,
  courseDuration,
  totalSelectedHours,
  timeStringToMinutes,
  selectedCompanies = [],
  selectedPersons = []
}: UseFormValidationProps): UseFormValidationReturn {

  // Validazione Step 0: Dettagli corso
  const step0Validation = useMemo(() => {
    const errors: ValidationError[] = [];

    // Validazione corso selezionato
    if (!selectedCourse) {
      errors.push({ field: 'course', message: 'Seleziona un corso' });
    }

    // Validazione livello di rischio (richiesto solo se opzioni > 1)
    if ((dynamicRiskOptions.length > 1) && !formData.risk_level) {
      errors.push({ field: 'risk_level', message: 'Seleziona il livello di rischio' });
    }

    // Validazione tipo corso (richiesto solo se opzioni > 1)
    if ((dynamicCourseTypeOptions.length > 1) && !formData.course_type) {
      errors.push({ field: 'course_type', message: 'Seleziona il tipo di corso' });
    }

    // Validazione modalità di erogazione
    if (!formData.delivery_mode) {
      errors.push({ field: 'delivery_mode', message: 'Seleziona la modalità di erogazione' });
    }

    // Validazione date, orari e formatori per data
    if (!formData.dates || formData.dates.length === 0) {
      errors.push({ field: 'dates', message: 'Aggiungi almeno una data' });
    } else {
      formData.dates.forEach((date, index) => {
        if (!date.date) {
          errors.push({ field: `dates.${index}.date`, message: `Data ${index + 1} è obbligatoria` });
        }
        if (!date.start) {
          errors.push({ field: `dates.${index}.start`, message: `Orario inizio ${index + 1} è obbligatorio` });
        }
        if (!date.end) {
          errors.push({ field: `dates.${index}.end`, message: `Orario fine ${index + 1} è obbligatorio` });
        }

        // Validazione logica orari
        if (date.start && date.end) {
          const startMinutes = timeStringToMinutes(date.start);
          const endMinutes = timeStringToMinutes(date.end);
          if (startMinutes >= endMinutes) {
            errors.push({ 
              field: `dates.${index}.time`, 
              message: `L'orario di fine deve essere successivo all'orario di inizio per la data ${index + 1}` 
            });
          }
        }

        // Validazione trainer per data (accesso tipizzato)
        const trainerId = (date as { trainerId?: string | number }).trainerId;
        if (!trainerId || String(trainerId).trim() === '') {
          errors.push({ field: `dates.${index}.trainerId`, message: `Seleziona un formatore per la sessione ${index + 1}` });
        }
        const coTrainerId = (date as { coTrainerId?: string | number }).coTrainerId;
        if (trainerId && coTrainerId && String(trainerId) === String(coTrainerId)) {
          errors.push({ field: `dates.${index}.coTrainerId`, message: `Il co-formatore non può coincidere con il formatore nella sessione ${index + 1}` });
        }
      });
    }

    return {
      isValid: errors.length === 0,
      errors,
      fieldErrors: errors.reduce((acc, error) => ({ ...acc, [error.field]: error.message }), {})
    };
  }, [formData, selectedCourse, dynamicRiskOptions, dynamicCourseTypeOptions, timeStringToMinutes]);

  // Validazione Step 1: Selezione aziende
  const step1Validation = useMemo(() => {
    const errors: ValidationError[] = [];

    if (!selectedCompanies || selectedCompanies.length === 0) {
      errors.push({ field: 'companies', message: 'Seleziona almeno un\'azienda' });
    }

    return {
      isValid: errors.length === 0,
      errors,
      fieldErrors: errors.reduce((acc, error) => ({ ...acc, [error.field]: error.message }), {})
    };
  }, [selectedCompanies]);

  // Validazione Step 2: Presenze
  const step2Validation = useMemo(() => {
    const errors: ValidationError[] = [];

    if (!selectedPersons || selectedPersons.length === 0) {
      errors.push({ field: 'persons', message: 'Seleziona almeno un partecipante' });
    }

    return {
      isValid: errors.length === 0,
      errors,
      fieldErrors: errors.reduce((acc, error) => ({ ...acc, [error.field]: error.message }), {})
    };
  }, [selectedPersons]);

  // Validazione Step 3: Documenti (opzionale)
  const step3Validation = useMemo(() => {
    return {
      isValid: true,
      errors: [],
      fieldErrors: {}
    };
  }, []);

  // Validazione Step 4: Riepilogo (sempre valido se si arriva qui)
  const step4Validation = useMemo(() => {
    return {
      isValid: true,
      errors: [],
      fieldErrors: {}
    };
  }, []);

  // Validazione step corrente
  const currentStepValidation = useMemo(() => {
    switch (currentStep) {
      case 0: return step0Validation;
      case 1: return step1Validation;
      case 2: return step2Validation;
      case 3: return step3Validation;
      case 4: return step4Validation;
      default: return { isValid: false, errors: [], fieldErrors: {} };
    }
  }, [currentStep, step0Validation, step1Validation, step2Validation, step3Validation, step4Validation]);

  // Validazione completa di tutti gli step
  const allStepsValidation = useMemo(() => {
    const allErrors = [
      ...step0Validation.errors,
      ...step1Validation.errors,
      ...step2Validation.errors,
      ...step3Validation.errors,
      ...step4Validation.errors
    ];

    return {
      isValid: allErrors.length === 0,
      errors: allErrors,
      fieldErrors: allErrors.reduce((acc, error) => ({ ...acc, [error.field]: error.message }), {})
    };
  }, [step0Validation, step1Validation, step2Validation, step3Validation, step4Validation]);

  // Funzioni di validazione
  const validateCurrentStep = useCallback(() => currentStepValidation, [currentStepValidation]);
  const validateAllSteps = useCallback(() => allStepsValidation, [allStepsValidation]);

  const validateField = useCallback((field: string, value: unknown): ValidationError | null => {
    // Implementazione validazione singolo campo
    switch (field) {
      case 'course':
        return !value ? { field, message: 'Seleziona un corso' } : null;
      case 'risk_level':
        return (dynamicRiskOptions.length > 1) && !value ? { field, message: 'Seleziona il livello di rischio' } : null;
      case 'course_type':
        return (dynamicCourseTypeOptions.length > 1) && !value ? { field, message: 'Seleziona il tipo di corso' } : null;
      case 'delivery_mode':
        return !value ? { field, message: 'Seleziona la modalità di erogazione' } : null;
      // La validazione del formatore è gestita per-data (dates[i].trainerId)
      case 'trainer_id':
        return null;
      default:
        return null;
    }
  }, [dynamicRiskOptions, dynamicCourseTypeOptions]);

  const clearErrors = useCallback(() => {
    // Questa funzione può essere utilizzata per pulire gli errori
    // L'implementazione dipende da come si vuole gestire lo stato degli errori
  }, []);

  return {
    // Validation results
    isValid: currentStepValidation.isValid,
    errors: currentStepValidation.errors,
    fieldErrors: currentStepValidation.fieldErrors,

    // Step-specific validation
    isStep0Valid: step0Validation.isValid,
    isStep1Valid: step1Validation.isValid,
    isStep2Valid: step2Validation.isValid,
    isStep3Valid: step3Validation.isValid,
    isStep4Valid: step4Validation.isValid,

    // Validation functions
    validateCurrentStep,
    validateAllSteps,
    validateField,
    clearErrors
  };
}

export default useFormValidation;

import React, { useState, useCallback, useMemo, useEffect, createContext, useContext } from 'react';
import { validateScheduleForm, timeStringToMinutes as timeStringToMinutesUtil, computeTotalSelectedMinutes, toIdString, getPersonIdsForCompanyUniversal } from '../utils';
import { getTrainers } from '../../../services/trainers';
import type { RiskLevel, CourseType, DeliveryMode } from '../../../constants/scheduleModal';
import type { Training, Person } from '../types';

// Types consolidati
export interface FormData {
  training_id: string | number;
  trainer_id: string | number;
  co_trainer_id: string | number;
  dates: Array<{
    date: string;
    start: string;
    end: string;
    trainerId: string | number;
    coTrainerId: string | number;
  }>;
  location: string;
  max_participants: number;
  notes: string;
  delivery_mode: DeliveryMode | '';
  risk_level: RiskLevel | '';
  course_type: CourseType | '';
}

type Trainer = import('../utils').Trainer;

// Evento esistente (forma tollerante)
interface ExistingEvent {
  id?: string | number;
  training_id?: string | number;
  course?: { id?: string | number; riskLevel?: string; courseType?: string };
  dates?: Array<{
    date: string;
    start: string;
    end: string;
    trainer_id?: string | number;
    co_trainer_id?: string | number;
    trainerId?: string | number;
    coTrainerId?: string | number;
  }>;
  location?: string;
  max_participants?: number;
  notes?: string;
  delivery_mode?: string;
  risk_level?: string;
  course_type?: string;
  employees?: Array<{ id: string | number }>;
  employee_ids?: Array<string | number>;
  companies?: Array<{ id: string | number }>;
  company_ids?: Array<string | number>;
}

export interface ScheduleContextState {
  // Form Data State
  formData: FormData;
  setFormData: React.Dispatch<React.SetStateAction<FormData>>;

  // Selections State
  selectedCompanies: (string | number)[];
  selectedPersons: (string | number)[];
  setSelectedCompanies: React.Dispatch<React.SetStateAction<(string | number)[]>>;
  setSelectedPersons: React.Dispatch<React.SetStateAction<(string | number)[]>>;

  // Modal State
  loading: boolean;
  setLoading: (loading: boolean) => void;
  error: string | null;
  setError: (error: string | null) => void;
  hasScheduled: boolean;
  setHasScheduled: (hasScheduled: boolean) => void;
  scheduleId: string | number | null;
  setScheduleId: (scheduleId: string | number | null) => void;

  // Search States
  courseSearch: string;
  setCourseSearch: (search: string) => void;
  companySearch: string;
  setCompanySearch: (search: string) => void;
  personSearch: string;
  setPersonSearch: (search: string) => void;
  personTab: string | number;
  setPersonTab: (tab: string | number) => void;
  selectedDayIdx: number;
  setSelectedDayIdx: (idx: number) => void;
  showStatusMenu: boolean;
  setShowStatusMenu: (show: boolean) => void;

  // Status State
  status: string;
  setStatus: (status: string) => void;

  // Trainers State
  effectiveTrainers: Trainer[];

  // Computed Values
  isEditing: boolean;
  totalSelectedMinutes: number;
  totalSelectedHours: number;
  courseDuration: number;
  hoursLeft: number;

  // Handlers
  handleFormDataChange: (field: string, value: unknown) => void;
  handleUpdateDateTime: (idx: number, field: 'date' | 'start' | 'end' | 'trainerId' | 'coTrainerId', value: string) => void;
  handleAddDateTime: () => void;
  handleRemoveDateTime: (idx: number) => void;
  handleCompanyToggle: (companyId: string | number) => void;
  handlePersonToggle: (personId: string | number) => void;
  handleSelectAllPersons: (companyId: string | number) => void;
  handleDeselectAllPersons: (companyId: string | number) => void;
  getPersonIdsForCompany: (companyId: string) => (string | number)[];
  validateAll: () => boolean;
}

export interface UseScheduleContextProps {
  existingEvent?: ExistingEvent;
  initialDate?: string;
  initialTime?: { start: string; end: string };
  selectedCourse?: Training;
  dynamicRiskOptions: Array<{ value: string; label: string }>;
  dynamicCourseTypeOptions: Array<{ value: string; label: string }>;
  trainers?: Trainer[];
  persons: Person[];
}

// Context
const ScheduleContext = createContext<ScheduleContextState | null>(null);

export function useScheduleContext(): ScheduleContextState {
  const context = useContext(ScheduleContext);
  if (!context) {
    throw new Error('useScheduleContext must be used within a ScheduleContextProvider');
  }
  return context;
}

// Hook consolidato
export function useScheduleContextState({
  existingEvent = {},
  initialDate,
  initialTime,
  selectedCourse,
  dynamicRiskOptions,
  dynamicCourseTypeOptions,
  trainers,
  persons,
}: UseScheduleContextProps): ScheduleContextState {

  // === FORM DATA STATE ===
  const [formError, setFormError] = useState<string | null>(null);

  // Initialize form data (da useFormData)
  const initialFormData = useMemo((): FormData => {
    const isEditing = existingEvent && Object.keys(existingEvent).length > 0;

    if (isEditing) {
      const event = existingEvent as ExistingEvent;
      const course = event.course;
      const dates = event.dates || [];

      return {
        training_id: (event.training_id as string | number) || (course?.id as string | number) || '',
        trainer_id: '',
        co_trainer_id: '',
        dates: dates.map((d) => ({
          date: d.date,
          start: d.start,
          end: d.end,
          trainerId: (d.trainer_id ?? d.trainerId) as string | number,
          coTrainerId: (d.co_trainer_id ?? d.coTrainerId) as string | number,
        })),
        location: event.location || '',
        max_participants: event.max_participants || 20,
        notes: event.notes || '',
        delivery_mode: (event.delivery_mode as string) || '',
        risk_level: (event.risk_level as string) || (course?.riskLevel as string) || '',
        course_type: (event.course_type as string) || (course?.courseType as string) || '',
      };
    }

    return {
      training_id: '',
      trainer_id: '',
      co_trainer_id: '',
      dates: [{
        date: initialDate || new Date().toISOString().split('T')[0],
        start: initialTime?.start || '09:00',
        end: initialTime?.end || '13:00',
        trainerId: '',
        coTrainerId: '',
      }],
      location: '',
      max_participants: 20,
      notes: '',
      delivery_mode: '',
      risk_level: '',
      course_type: '',
    };
  }, [existingEvent, initialDate, initialTime]);

  const [formData, setFormData] = useState<FormData>(initialFormData);

  // === SELECTIONS STATE ===
  // Initialize selections from existing event (da useSelections)
  const eventSel = existingEvent as ExistingEvent;
  const normalizedSel = useMemo(() => ({
    companyIds: eventSel?.company_ids ?? eventSel?.companies?.map(c => c.id) ?? [],
    personIds: eventSel?.employee_ids ?? eventSel?.employees?.map(e => e.id) ?? [],
  }), [eventSel]);

  const [selectedCompanies, setSelectedCompanies] = useState<(string | number)[]>(
    normalizedSel.companyIds as (string | number)[]
  );

  const [selectedPersons, setSelectedPersons] = useState<(string | number)[]>(
    normalizedSel.personIds as (string | number)[]
  );

  // === MODAL STATE ===
  // Fallback trainers state (da useScheduleModalState)
  const [fallbackTrainers, setFallbackTrainers] = useState<Trainer[]>([]);
  const effectiveTrainers = useMemo(() => 
    (trainers && trainers.length > 0 ? trainers : fallbackTrainers), 
    [trainers, fallbackTrainers]
  );

  useEffect(() => {
    let isCancelled = false;
    if (!trainers || trainers.length === 0) {
      (async () => {
        try {
          const items = await getTrainers();
          if (!isCancelled) setFallbackTrainers(items || []);
        } catch (e) {
          // ignore
        }
      })();
    }
    return () => { isCancelled = true; };
  }, [trainers]);

  // Core state
  const isEditing = existingEvent && Object.keys(existingEvent).length > 0;
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [hasScheduled, setHasScheduled] = useState(isEditing);
  const [scheduleId, setScheduleId] = useState<string | number | null>(
    (eventSel?.id as string | number | undefined) ?? null
  );

  // Search states
  const [courseSearch, setCourseSearch] = useState('');
  const [companySearch, setCompanySearch] = useState('');
  const [personSearch, setPersonSearch] = useState('');
  const [personTab, setPersonTab] = useState<string | number>('');
  const [selectedDayIdx, setSelectedDayIdx] = useState(0);
  const [showStatusMenu, setShowStatusMenu] = useState(false);

  // Status state
  const [status, setStatus] = useState('Preventivo');

  // === EFFECTS ===
  // Auto-fill risk/course type if defined on course
  useEffect(() => {
    if (!selectedCourse) return;
    setFormData(prev => {
      const updates: Record<string, unknown> = {};
      if (!prev.risk_level && selectedCourse.riskLevel) updates.risk_level = selectedCourse.riskLevel as string;
      if (!prev.course_type && selectedCourse.courseType) updates.course_type = selectedCourse.courseType as string;
      return Object.keys(updates).length ? { ...prev, ...updates } : prev;
    });
  }, [selectedCourse]);

  // Auto-select risk/type when only one option is available; clear when none
  useEffect(() => {
    // Risk
    if ((dynamicRiskOptions?.length || 0) === 1 && !formData.risk_level) {
      setFormData(prev => ({ ...prev, risk_level: dynamicRiskOptions[0].value }));
    } else if ((dynamicRiskOptions?.length || 0) === 0 && formData.risk_level) {
      setFormData(prev => ({ ...prev, risk_level: '' }));
    }
    // Course type
    if ((dynamicCourseTypeOptions?.length || 0) === 1 && !formData.course_type) {
      setFormData(prev => ({ ...prev, course_type: dynamicCourseTypeOptions[0].value }));
    } else if ((dynamicCourseTypeOptions?.length || 0) === 0 && formData.course_type) {
      setFormData(prev => ({ ...prev, course_type: '' }));
    }
  }, [dynamicRiskOptions, dynamicCourseTypeOptions, formData.risk_level, formData.course_type]);

  // === COMPUTED VALUES ===
  const timeStringToMinutes = timeStringToMinutesUtil;

  const totalSelectedMinutes = useMemo(() => 
    computeTotalSelectedMinutes(formData.dates, timeStringToMinutes), 
    [formData.dates, timeStringToMinutes]
  );

  const totalSelectedHours = useMemo(() => 
    Math.round((totalSelectedMinutes / 60) * 100) / 100, 
    [totalSelectedMinutes]
  );

  const courseDuration = useMemo(() => {
    if (!selectedCourse?.duration) return 0;
    return typeof selectedCourse.duration === 'number' ? selectedCourse.duration : parseFloat(String(selectedCourse.duration)) || 0;
  }, [selectedCourse]);

  const hoursLeft = useMemo(() => 
    Math.max(0, courseDuration - totalSelectedHours), 
    [courseDuration, totalSelectedHours]
  );

  // === HANDLERS ===
  // Form handlers
  const handleFormDataChange = useCallback((field: string, value: unknown) => {
    setFormData(prev => ({ ...prev, [field]: value }));
  }, []);

  const handleUpdateDateTime = useCallback((idx: number, field: 'date' | 'start' | 'end' | 'trainerId' | 'coTrainerId', value: string) => {
    setFormData(prev => ({
      ...prev,
      dates: prev.dates.map((date, i) => 
        i === idx ? { ...date, [field]: value } : date
      )
    }));
  }, []);

  const handleAddDateTime = useCallback(() => {
    setFormData(prev => ({
      ...prev,
      dates: [...prev.dates, { date: '', start: '09:00', end: '13:00', trainerId: '', coTrainerId: '' }]
    }));
  }, []);

  const handleRemoveDateTime = useCallback((idx: number) => {
    setFormData(prev => ({
      ...prev,
      dates: prev.dates.filter((_, i) => i !== idx)
    }));
  }, []);

  // Selection handlers
  const getPersonIdsForCompany = useCallback((companyId: string) => {
    return getPersonIdsForCompanyUniversal(persons, companyId);
  }, [persons]);

  const handleCompanyToggle = useCallback((companyId: string | number) => {
    const id = String(companyId);
    setSelectedCompanies(prev => {
      const prevSet = new Set(prev.map(String));
      if (prevSet.has(id)) {
        return prev.filter(existingId => String(existingId) !== id);
      }
      return Array.from(new Set([...prev.map(String), id]));
    });
  }, []);

  const handlePersonToggle = useCallback((personId: string | number) => {
    const id = String(personId);
    setSelectedPersons(prev => {
      const prevSet = new Set(prev.map(String));
      if (prevSet.has(id)) {
        return prev.filter(existingId => String(existingId) !== id);
      }
      return Array.from(new Set([...prev.map(String), id]));
    });
  }, []);

  const handleSelectAllPersons = useCallback((companyId: string | number) => {
    const companyPersonIds = getPersonIdsForCompany(String(companyId)).map(String);
    setSelectedPersons(prev => Array.from(new Set([...prev.map(String), ...companyPersonIds])));
  }, [getPersonIdsForCompany]);

  const handleDeselectAllPersons = useCallback((companyId: string | number) => {
    const companyPersonIds = new Set(getPersonIdsForCompany(String(companyId)).map(String));
    setSelectedPersons(prev => prev.filter(id => !companyPersonIds.has(String(id))));
  }, [getPersonIdsForCompany]);

  // Validation
  const validateAll = useCallback(() => {
    const result = validateScheduleForm(
      formData,
      dynamicRiskOptions,
      dynamicCourseTypeOptions,
      timeStringToMinutes,
      courseDuration,
      totalSelectedHours
    );
    if (!result.valid) {
      setError(result.error);
      return false;
    }
    setError(null);
    return true;
  }, [formData, dynamicRiskOptions, dynamicCourseTypeOptions, courseDuration, totalSelectedHours]);

  return {
    // Form Data State
    formData,
    setFormData,

    // Selections State
    selectedCompanies,
    selectedPersons,
    setSelectedCompanies,
    setSelectedPersons,

    // Modal State
    loading,
    setLoading,
    error: error || formError,
    setError: (err: string | null) => {
      setError(err);
      setFormError(err);
    },
    hasScheduled,
    setHasScheduled,
    scheduleId,
    setScheduleId,

    // Search States
    courseSearch,
    setCourseSearch,
    companySearch,
    setCompanySearch,
    personSearch,
    setPersonSearch,
    personTab,
    setPersonTab,
    selectedDayIdx,
    setSelectedDayIdx,
    showStatusMenu,
    setShowStatusMenu,

    // Status State
    status,
    setStatus,

    // Trainers State
    effectiveTrainers,

    // Computed Values
    isEditing,
    totalSelectedMinutes,
    totalSelectedHours,
    courseDuration,
    hoursLeft,

    // Handlers
    handleFormDataChange,
    handleUpdateDateTime,
    handleAddDateTime,
    handleRemoveDateTime,
    handleCompanyToggle,
    handlePersonToggle,
    handleSelectAllPersons,
    handleDeselectAllPersons,
    getPersonIdsForCompany,
    validateAll,
  };
}

// Provider Component
