export function useScheduleModalState({
  trainers,
  existingEvent = {}
}: UseScheduleModalStateProps): UseScheduleModalStateReturn {
  // Fallback trainers state
  const [fallbackTrainers, setFallbackTrainers] = useState<Trainer[]>([]);
  const effectiveTrainers = useMemo(() => 
    (trainers && trainers.length > 0 ? trainers : fallbackTrainers), 
    [trainers, fallbackTrainers]
  );

  useEffect(() => {
    let isCancelled = false;
    if (!trainers || trainers.length === 0) {
      (async () => {
        try {
          const items = await getTrainers();
          if (!isCancelled) setFallbackTrainers(items || []);
        } catch (e) {
          // ignore
        }
      })();
    }
    return () => { isCancelled = true; };
  }, [trainers]);

  // Core state
  const isEditing = existingEvent && Object.keys(existingEvent).length > 0;
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [hasScheduled, setHasScheduled] = useState(isEditing);
  const [scheduleId, setScheduleId] = useState<string | number | null>(
    (existingEvent as Record<string, unknown>)?.id as string | number || null
  );

  // Search states
  const [courseSearch, setCourseSearch] = useState('');
  const [companySearch, setCompanySearch] = useState('');
  const [personSearch, setPersonSearch] = useState('');
  const [personTab, setPersonTab] = useState<string | number>('');
  const [selectedDayIdx, setSelectedDayIdx] = useState(0);
  const [showStatusMenu, setShowStatusMenu] = useState(false);

  // Status state
  const [status, setStatus] = useState('Preventivo');

  return {
    // Core state
    loading,
    setLoading,
    error,
    setError,
    hasScheduled,
    setHasScheduled,
    scheduleId,
    setScheduleId,

    // Trainers state
    effectiveTrainers,

    // Search states
    courseSearch,
    setCourseSearch,
    companySearch,
    setCompanySearch,
    personSearch,
    setPersonSearch,
    personTab,
    setPersonTab,
    selectedDayIdx,
    setSelectedDayIdx,
    showStatusMenu,
    setShowStatusMenu,

    // Status state
    status,
    setStatus,

    // Computed values
    isEditing
  };
}

import { useReducer, useEffect, useMemo } from 'react';
import { getTrainers } from '../../../services/trainers';
import type { ScheduleEventModalProps } from '../ScheduleEventModal.lazy';

type Trainer = import('../utils').Trainer;

interface UseScheduleModalStateProps {
  trainers?: Trainer[];
  existingEvent?: Record<string, unknown>;
}

// Consolidated state interface
interface ModalState {
  // Core state
  loading: boolean;
  error: string | null;
  hasScheduled: boolean;
  scheduleId: string | number | null;

  // Search states
  courseSearch: string;
  companySearch: string;
  personSearch: string;
  personTab: string | number;
  selectedDayIdx: number;
  showStatusMenu: boolean;

  // Status state
  status: string;

  // Trainers state
  fallbackTrainers: Trainer[];
}

// Action types
type ModalAction = 
  | { type: 'SET_LOADING'; payload: boolean }
  | { type: 'SET_ERROR'; payload: string | null }
  | { type: 'SET_HAS_SCHEDULED'; payload: boolean }
  | { type: 'SET_SCHEDULE_ID'; payload: string | number | null }
  | { type: 'SET_COURSE_SEARCH'; payload: string }
  | { type: 'SET_COMPANY_SEARCH'; payload: string }
  | { type: 'SET_PERSON_SEARCH'; payload: string }
  | { type: 'SET_PERSON_TAB'; payload: string | number }
  | { type: 'SET_SELECTED_DAY_IDX'; payload: number }
  | { type: 'SET_SHOW_STATUS_MENU'; payload: boolean }
  | { type: 'SET_STATUS'; payload: string }
  | { type: 'SET_FALLBACK_TRAINERS'; payload: Trainer[] }
  | { type: 'RESET_SEARCHES' }
  | { type: 'RESET_ALL' };

// Reducer function
function modalStateReducer(state: ModalState, action: ModalAction): ModalState {
  switch (action.type) {
    case 'SET_LOADING':
      return { ...state, loading: action.payload };
    case 'SET_ERROR':
      return { ...state, error: action.payload };
    case 'SET_HAS_SCHEDULED':
      return { ...state, hasScheduled: action.payload };
    case 'SET_SCHEDULE_ID':
      return { ...state, scheduleId: action.payload };
    case 'SET_COURSE_SEARCH':
      return { ...state, courseSearch: action.payload };
    case 'SET_COMPANY_SEARCH':
      return { ...state, companySearch: action.payload };
    case 'SET_PERSON_SEARCH':
      return { ...state, personSearch: action.payload };
    case 'SET_PERSON_TAB':
      return { ...state, personTab: action.payload };
    case 'SET_SELECTED_DAY_IDX':
      return { ...state, selectedDayIdx: action.payload };
    case 'SET_SHOW_STATUS_MENU':
      return { ...state, showStatusMenu: action.payload };
    case 'SET_STATUS':
      return { ...state, status: action.payload };
    case 'SET_FALLBACK_TRAINERS':
      return { ...state, fallbackTrainers: action.payload };
    case 'RESET_SEARCHES':
      return {
        ...state,
        courseSearch: '',
        companySearch: '',
        personSearch: '',
        personTab: '',
        selectedDayIdx: 0
      };
    case 'RESET_ALL':
      return {
        ...state,
        loading: false,
        error: null,
        courseSearch: '',
        companySearch: '',
        personSearch: '',
        personTab: '',
        selectedDayIdx: 0,
        showStatusMenu: false
      };
    default:
      return state;
  }
}

// Initial state factory
function createInitialState(existingEvent: Record<string, unknown>): ModalState {
  const isEditing = existingEvent && Object.keys(existingEvent).length > 0;

  return {
    loading: false,
    error: null,
    hasScheduled: isEditing,
    scheduleId: (existingEvent?.id as string | number) || null,
    courseSearch: '',
    companySearch: '',
    personSearch: '',
    personTab: '',
    selectedDayIdx: 0,
    showStatusMenu: false,
    status: 'Preventivo',
    fallbackTrainers: []
  };
}

interface UseScheduleModalStateReturn {
  // Core state
  loading: boolean;
  setLoading: (loading: boolean) => void;
  error: string | null;
  setError: (error: string | null) => void;
  hasScheduled: boolean;
  setHasScheduled: (hasScheduled: boolean) => void;
  scheduleId: string | number | null;
  setScheduleId: (scheduleId: string | number | null) => void;

  // Trainers state
  effectiveTrainers: Trainer[];

  // Search states
  courseSearch: string;
  setCourseSearch: (search: string) => void;
  companySearch: string;
  setCompanySearch: (search: string) => void;
  personSearch: string;
  setPersonSearch: (search: string) => void;
  personTab: string | number;
  setPersonTab: (tab: string | number) => void;
  selectedDayIdx: number;
  setSelectedDayIdx: (idx: number) => void;
  showStatusMenu: boolean;
  setShowStatusMenu: (show: boolean) => void;

  // Status state
  status: string;
  setStatus: (status: string) => void;

  // Computed values
  isEditing: boolean;

  // Utility functions
  resetSearches: () => void;
  resetAll: () => void;
}

export function useScheduleModalStateOptimized({
  trainers,
  existingEvent = {}
}: UseScheduleModalStateProps): UseScheduleModalStateReturn {
  // Initialize state with useReducer
  const [state, dispatch] = useReducer(
    modalStateReducer,
    existingEvent,
    createInitialState
  );

  // Memoized effective trainers
  const effectiveTrainers = useMemo(() => 
    (trainers && trainers.length > 0 ? trainers : state.fallbackTrainers), 
    [trainers, state.fallbackTrainers]
  );

  // Fetch fallback trainers if needed
  useEffect(() => {
    let isCancelled = false;
    if (!trainers || trainers.length === 0) {
      (async () => {
        try {
          const items = await getTrainers();
          if (!isCancelled) {
            dispatch({ type: 'SET_FALLBACK_TRAINERS', payload: items || [] });
          }
        } catch (e) {
          // ignore
        }
      })();
    }
    return () => { isCancelled = true; };
  }, [trainers]);

  // Computed values
  const isEditing = existingEvent && Object.keys(existingEvent).length > 0;

  // Action creators
  const setLoading = (loading: boolean) => dispatch({ type: 'SET_LOADING', payload: loading });
  const setError = (error: string | null) => dispatch({ type: 'SET_ERROR', payload: error });
  const setHasScheduled = (hasScheduled: boolean) => dispatch({ type: 'SET_HAS_SCHEDULED', payload: hasScheduled });
  const setScheduleId = (scheduleId: string | number | null) => dispatch({ type: 'SET_SCHEDULE_ID', payload: scheduleId });
  const setCourseSearch = (search: string) => dispatch({ type: 'SET_COURSE_SEARCH', payload: search });
  const setCompanySearch = (search: string) => dispatch({ type: 'SET_COMPANY_SEARCH', payload: search });
  const setPersonSearch = (search: string) => dispatch({ type: 'SET_PERSON_SEARCH', payload: search });
  const setPersonTab = (tab: string | number) => dispatch({ type: 'SET_PERSON_TAB', payload: tab });
  const setSelectedDayIdx = (idx: number) => dispatch({ type: 'SET_SELECTED_DAY_IDX', payload: idx });
  const setShowStatusMenu = (show: boolean) => dispatch({ type: 'SET_SHOW_STATUS_MENU', payload: show });
  const setStatus = (status: string) => dispatch({ type: 'SET_STATUS', payload: status });
  const resetSearches = () => dispatch({ type: 'RESET_SEARCHES' });
  const resetAll = () => dispatch({ type: 'RESET_ALL' });

  return {
    // Core state
    loading: state.loading,
    setLoading,
    error: state.error,
    setError,
    hasScheduled: state.hasScheduled,
    setHasScheduled,
    scheduleId: state.scheduleId,
    setScheduleId,

    // Trainers state
    effectiveTrainers,

    // Search states
    courseSearch: state.courseSearch,
    setCourseSearch,
    companySearch: state.companySearch,
    setCompanySearch,
    personSearch: state.personSearch,
    setPersonSearch,
    personTab: state.personTab,
    setPersonTab,
    selectedDayIdx: state.selectedDayIdx,
    setSelectedDayIdx,
    showStatusMenu: state.showStatusMenu,
    setShowStatusMenu,

    // Status state
    status: state.status,
    setStatus,

    // Computed values
    isEditing,

    // Utility functions
    resetSearches,
    resetAll
  };
}

export default useScheduleModalStateOptimized;

import { useMemo } from 'react';
import type { Training, Trainer, CertificateFilter } from '../types';
import { computeTrainerCertFilter, filterTrainersByCerts } from '../utils';

export interface UseTrainerFiltersParams {
  selectedCourse: Training | undefined;
  selectedCourseVariants: Training[] | undefined;
  trainings: Training[];
  formData: { risk_level?: string; course_type?: string; training_id?: string | number };
  trainers: Trainer[];
  normalizeText: (s?: unknown) => string;
  expandTerms: (term: string) => string[];
}

export interface UseTrainerFiltersResult {
  filteredTrainers: Trainer[];           // with fallback to all trainers when filter is empty
  strictFiltered: Trainer[];             // only qualified trainers (may be empty)
  coTrainerOptions: Trainer[];           // currently all trainers
  trainerCertFilter: CertificateFilter;  // exposed for debugging/insights
}

export function useTrainerFilters(params: UseTrainerFiltersParams): UseTrainerFiltersResult {
  const { selectedCourse, selectedCourseVariants, trainings, formData, trainers, normalizeText, expandTerms } = params;

  const trainerCertFilter = useMemo(() => {
    return computeTrainerCertFilter(
      selectedCourse,
      selectedCourseVariants,
      trainings,
      formData,
      normalizeText,
      expandTerms
    );
  }, [selectedCourse, selectedCourseVariants, trainings, formData?.risk_level, formData?.course_type, formData?.training_id, normalizeText, expandTerms]);

  const strictFiltered = useMemo(() => {
    return filterTrainersByCerts(trainers || [], trainerCertFilter, normalizeText);
  }, [trainers, trainerCertFilter, normalizeText]);

  const filteredTrainers = useMemo(() => {
    return (strictFiltered && strictFiltered.length > 0) ? strictFiltered : (trainers || []);
  }, [strictFiltered, trainers]);

  const coTrainerOptions = useMemo(() => trainers || [], [trainers]);

  return { filteredTrainers, strictFiltered, coTrainerOptions, trainerCertFilter };
}

// Shared utilities for schedules module: text normalization, certificate synonyms, extraction helpers, time/date utils

import type { ScheduleDateEntry, Option, Person, ScheduleFormData, ValidationResult } from './types';
import { RISK_LEVEL_OPTIONS, COURSE_TYPE_OPTIONS } from '../../constants/scheduleModal';

export const normalizeText = (s?: unknown): string =>
  String(s ?? '')
    .toLowerCase()
    .normalize('NFD').replace(/[\u0300-\u036f]/g, '')
    .replace(/&/g, ' e ')
    .replace(/[^a-z0-9]+/gi, ' ')
    .replace(/\s+/g, ' ')
    .trim();

// Sinonimi/alias per certificazioni corsi e formatori (normalizzati)
export const CERT_SYNONYMS: Record<string, string[]> = {
  sanitario: ['sanitario', 'blsd', 'bls d', 'bls', 'dae', 'defibrillatore', 'irc'],
  'primo soccorso': ['primo soccorso', 'addetto primo soccorso', 'ps', 'blsd', 'bls'],
  antincendio: ['antincendio', 'addetto antincendio', 'rischio basso', 'rischio medio', 'rischio alto'],
  'sicurezza generale': ['sicurezza generale', 'formazione generale', 'lavoratori generale'],
  'sicurezza specifica': ['sicurezza specifica', 'formazione specifica', 'lavoratori specifica', 'basso', 'medio', 'alto'],
  'preposto': ['preposto', 'formazione preposti', 'aggiornamento preposti'],
  'rspp': ['rspp', 'responsabile servizio prevenzione e protezione'],
  'aspp': ['aspp', 'addetto servizio prevenzione e protezione'],
};

export const expandTerms = (term: string): string[] => {
  const t = normalizeText(term);
  const out = new Set<string>([t]);
  Object.entries(CERT_SYNONYMS).forEach(([k, arr]) => {
    const key = normalizeText(k);
    const arrNorm = arr.map(x => normalizeText(x));
    const matches = t.includes(key) || key.includes(t) || arrNorm.some(a => t.includes(a) || a.includes(t));
    if (matches) {
      arrNorm.forEach(x => out.add(x));
      out.add(key);
    }
  });
  return Array.from(out);
};

export const normalizeCertList = (certs?: string[] | string): string[] => {
  if (Array.isArray(certs)) return certs;
  if (typeof certs === 'string') return certs.split(',').map(c => c.trim()).filter(Boolean);
  return [];
};

// Generic extraction of course arrays from various API response shapes
export const extractCourses = (res: any): any[] => {
  if (Array.isArray(res)) return res as any[];
  if (Array.isArray(res?.courses)) return res.courses as any[];
  if (Array.isArray(res?.items)) return res.items as any[];
  if (Array.isArray(res?.results)) return res.results as any[];
  if (Array.isArray(res?.data)) return res.data as any[];
  return [] as any[];
};

export const toIdString = (value: unknown): string => {
  try {
    if (value == null) return '';
    return String((value as any).id ?? value);
  } catch {
    return '';
  }
};

export const timeStringToMinutes = (t: string): number => {
  const [h, m] = t.split(':').map(Number);
  return h * 60 + (m || 0);
};

export const formatDate = (isoDate: string): string => new Date(isoDate).toLocaleDateString('it-IT');

export const computeTrainerCertFilter = (
  selectedCourse: any,
  selectedCourseVariants: any[] | undefined,
  trainings: any[],
  formData: { risk_level?: string; course_type?: string },
  normalizeTextFn: (s?: unknown) => string = normalizeText,
  expandTermsFn: (term: string) => string[] = expandTerms
): { allOf: string[]; anyOf: string[] } => {
  const rawTitle = (selectedCourse as any)?.title || (selectedCourse as any)?.name;
  const title = normalizeTextFn(rawTitle || '');
  if (!title) return { allOf: [], anyOf: [] };

  const source = (selectedCourseVariants && Array.isArray(selectedCourseVariants) && selectedCourseVariants.length > 0)
    ? selectedCourseVariants
    : trainings;
  const variants = (source as any[]).filter((t: any) => normalizeTextFn((t.title || t.name) as string) === title);

  let filtered = variants;
  if (formData?.risk_level) filtered = filtered.filter((v: any) => String((v as any).riskLevel || '') === String(formData.risk_level));
  if (formData?.course_type) filtered = filtered.filter((v: any) => String((v as any).courseType || '') === String(formData.course_type));

  const lists: string[][] = filtered.map((v: any) => {
    const c1 = (v as any).certifications as unknown;
    if (Array.isArray(c1)) {
      const base = (c1 as unknown[]).map(s => normalizeTextFn(String(s))).filter(Boolean);
      return Array.from(new Set(base.flatMap(expandTermsFn)));
    }
    const c2 = (v as any).requiredCerts as unknown;
    if (Array.isArray(c2)) {
      const base = (c2 as unknown[]).map(s => normalizeTextFn(String(s))).filter(Boolean);
      return Array.from(new Set(base.flatMap(expandTermsFn)));
    }
    const d = (v as any).details as any;
    if (d && Array.isArray(d.certifications)) {
      const base = (d.certifications as unknown[]).map(s => normalizeTextFn(String(s))).filter(Boolean);
      return Array.from(new Set(base.flatMap(expandTermsFn)));
    }
    if (d && Array.isArray(d.requiredCerts)) {
      const base = (d.requiredCerts as unknown[]).map(s => normalizeTextFn(String(s))).filter(Boolean);
      return Array.from(new Set(base.flatMap(expandTermsFn)));
    }
    return [] as string[];
  }).filter(arr => arr.length > 0);

  if (lists.length === 0) return { allOf: [], anyOf: [] };

  const intersection = lists.reduce<string[]>((acc, curr) => acc.filter(x => curr.includes(x)), lists[0]);
  if (intersection.length > 0) return { allOf: Array.from(new Set(intersection)), anyOf: [] };

  const union = Array.from(new Set(lists.flat())).filter(Boolean);
  return { allOf: [], anyOf: union };
};

export const filterTrainersByCerts = (
  trainers: any[],
  filter: { allOf: string[]; anyOf: string[] },
  normalizeTextFn: (s?: unknown) => string = normalizeText
) => {
  return trainers.filter(trainer => {
    const raw = (trainer as any).certifications as unknown;
    const trainerCerts = Array.isArray(raw)
      ? (raw as unknown[]).map(s => normalizeTextFn(String(s))).filter(Boolean)
      : (typeof raw === 'string'
        ? (raw as string).split(',').map(s => normalizeTextFn(s)).filter(Boolean)
        : [] as string[]);

    const { allOf, anyOf } = filter || { allOf: [], anyOf: [] };
    const hasAll = (reqs: string[]) => reqs.every(req => trainerCerts.some(tc => tc.includes(req) || req.includes(tc)));
    const hasAny = (reqs: string[]) => reqs.some(req => trainerCerts.some(tc => tc.includes(req) || req.includes(tc)));

    if ((allOf?.length || 0) > 0) return hasAll(allOf);
    if ((anyOf?.length || 0) > 0) return hasAny(anyOf);
    return true;
  });
};

export const computeTotalSelectedMinutes = (
  dates: { start: string; end: string }[] = [],
  timeStringToMinutesFn: (t: string) => number = timeStringToMinutes
): number => {
  try {
    return (dates || []).reduce((acc: number, d: { start: string; end: string }) => {
      const diff = timeStringToMinutesFn(d.end) - timeStringToMinutesFn(d.start);
      return acc + Math.max(0, diff);
    }, 0);
  } catch {
    return 0;
  }
};

export const normalizeAttendanceData = (attendanceData: unknown): Record<number, (string | number)[]> => {
  if (!attendanceData) return {};

  if (Array.isArray(attendanceData)) {
    return attendanceData.reduce((acc, entry, idx) => {
      const session = entry as Record<string, unknown>;
      acc[idx] = (session?.employee_ids as (string | number)[]) || [];
      return acc;
    }, {} as Record<number, (string | number)[]>);
  }

  if (typeof attendanceData === 'object') {
    const result: Record<number, (string | number)[]> = {};
    const attendanceObj = attendanceData as Record<string, unknown>;
    Object.keys(attendanceObj).forEach((key, idx) => {
      const session = attendanceObj[key] as Record<string, unknown>;
      if (session && (session as any).attendees) {
        const attendees = (session as any).attendees as Record<string, Record<string, unknown>>;
        const presentIds = Object.values(attendees)
          .filter((a: Record<string, unknown>) => (a as any).attended)
          .map((a: Record<string, unknown>) => (a as any).id as string | number);
        result[idx] = presentIds;
      } else if (session && (session as any).employee_ids) {
        result[idx] = (session as any).employee_ids as (string | number)[];
      }
    });
    return result;
  }

  return {};
};

export const buildSchedulePayload = (
  formData: ScheduleFormData,
  selectedCompanies: (string | number)[],
  selectedPersons: (string | number)[],
  attendance: Record<number, (string | number)[]>,
  status: string,
  isEditing: boolean,
  scheduleId?: string | number | null
) => {
  const datesArr: ScheduleDateEntry[] = (formData?.dates ?? []) as ScheduleDateEntry[];
  const dates: string[] = datesArr.map(d => d.date);
  const startDateStr = dates.reduce((a, b) => (a < b ? a : b));
  const endDateStr = dates.reduce((a, b) => (a > b ? a : b));

  const firstDate = datesArr.find(d => d.date === startDateStr);
  const lastDate = datesArr.find(d => d.date === endDateStr);

  const startDateTimeLocal = `${startDateStr}T${firstDate?.start || '09:00'}:00`;
  const endDateTimeLocal = `${endDateStr}T${lastDate?.end || '17:00'}:00`;
  const startDateTimeISO = new Date(startDateTimeLocal).toISOString();
  const endDateTimeISO = new Date(endDateTimeLocal).toISOString();

  const attendanceArr = datesArr.map((dt, idx: number) => ({
    date: dt.date,
    employee_ids: attendance[idx] || []
  }));

  const validCompanyIds = (selectedCompanies || []).filter(id => id !== null && id !== undefined);
  const validPersonIds = (selectedPersons || []).filter(id => id !== null && id !== undefined);

  const schedulePayload: any = {
    courseId: formData.training_id,
    start_date: startDateTimeISO,
    end_date: endDateTimeISO,
    location: formData.location,
    max_participants: formData.max_participants,
    notes: formData.notes,
    delivery_mode: formData.delivery_mode,
    risk_level: formData.risk_level,
    course_type: formData.course_type,
    dates: datesArr.map(dt => ({
      date: dt.date,
      start: dt.start,
      end: dt.end,
      trainer_id: dt.trainerId,
      co_trainer_id: dt.coTrainerId,
    })),
    companies: validCompanyIds.map(id => ({ companyId: String(id) })),
    company_ids: validCompanyIds.map(id => String(id)),
    enrollments: validPersonIds.map(id => ({ employeeId: String(id) })),
    employee_ids: validPersonIds.map(id => String(id)),
    attendance: attendanceArr,
    status,
  };

  if (isEditing && scheduleId) {
    return { ...schedulePayload, id: scheduleId };
  }
  return schedulePayload;
};

export function validateScheduleForm(
  formData: Pick<ScheduleFormData, 'training_id' | 'risk_level' | 'course_type' | 'location' | 'dates'>,
  dynamicRiskOptions: Option[],
  dynamicCourseTypeOptions: Option[],
  timeStringToMinutes: (t: string) => number,
  courseDuration: number,
  totalSelectedHours: number
): ValidationResult {
  // Verifica se c'è un corso selezionato (può essere training_id o un macro-corso)
  if (!formData.training_id) {
    return { valid: false, error: 'Seleziona un corso' };
  }

  // Richiedi rischio e tipo solo se ci sono opzioni multiple disponibili
  const requireRisk = (dynamicRiskOptions?.length || 0) > 1;
  const requireType = (dynamicCourseTypeOptions?.length || 0) > 1;

  if (requireRisk && !formData.risk_level) {
    return { valid: false, error: 'Seleziona il livello di rischio' };
  }
  if (requireType && !formData.course_type) {
    return { valid: false, error: 'Seleziona se è primo corso o aggiornamento' };
  }
  if (!formData.location) {
    return { valid: false, error: 'Inserisci il luogo del corso' };
  }
  if (!formData.dates || formData.dates.length === 0) {
    return { valid: false, error: 'Aggiungi almeno una data' };
  }
  for (let i = 0; i < formData.dates.length; i++) {
    const d: ScheduleDateEntry = formData.dates[i] as ScheduleDateEntry;
    const sessionNum = i + 1;
    if (!d.date) {
      return { valid: false, error: `Inserisci la data per la sessione ${sessionNum}` };
    }
    if (!d.start || !d.end) {
      return { valid: false, error: `Inserisci orario di inizio e fine per la sessione ${sessionNum}` };
    }
    const diff = timeStringToMinutes(d.end) - timeStringToMinutes(d.start);
    if (!(diff > 0)) {
      return { valid: false, error: `Orario non valido nella sessione ${sessionNum}: l'orario di fine deve essere successivo all'inizio` };
    }
    if (!d.trainerId) {
      return { valid: false, error: `Seleziona il formatore per la sessione ${sessionNum}` };
    }
    if (d.coTrainerId && String(d.coTrainerId) === String(d.trainerId)) {
      return { valid: false, error: `Il co-formatore non può coincidere con il formatore nella sessione ${sessionNum}` };
    }
  }

  // Verifica durata solo se è definita e maggiore di 0
  if (courseDuration > 0 && Math.abs(totalSelectedHours - courseDuration) > 0.01) {
    return { valid: false, error: 'La somma delle ore selezionate non coincide con la durata del corso' };
  }

  return { valid: true, error: '' };
}

export function computeDynamicRiskAndTypeOptions(
  selectedCourse: any,
  selectedCourseVariants: any[] | undefined,
  trainings: any[],
  formData: { risk_level?: string; course_type?: string },
  normalizeText: (s: string) => string,
  RISK_LEVEL_OPTIONS: Option[],
  COURSE_TYPE_OPTIONS: Option[]
): { riskOpts: Option[]; typeOpts: Option[]; riskValid: boolean; typeValid: boolean; titleEmpty: boolean } {
  const rawTitle = (selectedCourse as any)?.title || (selectedCourse as any)?.name;
  const title = normalizeText(rawTitle || '');
  if (!title) {
    // Manteniamo le opzioni base per mostrare le pillole anche senza corso selezionato;
    // la UI le renderà non selezionabili quando selectedCourse è assente.
    const riskOpts = RISK_LEVEL_OPTIONS.slice();
    const typeOpts = COURSE_TYPE_OPTIONS.slice();
    const riskValid = !formData.risk_level || !!riskOpts.find(o => o.value === formData.risk_level);
    const typeValid = !formData.course_type || !!typeOpts.find(o => o.value === formData.course_type);
    return { riskOpts, typeOpts, riskValid, typeValid, titleEmpty: true };
  }
  const source = (selectedCourseVariants && Array.isArray(selectedCourseVariants) && selectedCourseVariants.length > 0) ? selectedCourseVariants : (trainings as any[]);
  const variants = (source as any[]).filter((t: any) => normalizeText((t.title || t.name)) === title);

  const filteredByRisk = formData.risk_level
    ? variants.filter((v: any) => String((v as any).riskLevel || '') === String(formData.risk_level))
    : variants;
  const filteredByType = formData.course_type
    ? variants.filter((v: any) => String((v as any).courseType || '') === String(formData.course_type))
    : variants;

  const riskSet = new Set<string>(filteredByType.map((v: any) => String((v as any).riskLevel || '')).filter(Boolean));
  const typeSet = new Set<string>(filteredByRisk.map((v: any) => String((v as any).courseType || '')).filter(Boolean));

  const riskOpts = RISK_LEVEL_OPTIONS.filter(o => riskSet.has(o.value));
  const typeOpts = COURSE_TYPE_OPTIONS.filter(o => typeSet.has(o.value));

  const riskValid = !formData.risk_level || !!riskOpts.find(o => o.value === formData.risk_level);
  const typeValid = !formData.course_type || !!typeOpts.find(o => o.value === formData.course_type);

  return { riskOpts, typeOpts, riskValid, typeValid, titleEmpty: false };
}

export function resolveVariantSelection(
  selectedCourse: any,
  selectedCourseVariants: any[] | undefined,
  trainings: any[],
  formData: { training_id?: string | number; risk_level?: string; course_type?: string },
  normalizeText: (s: string) => string,
  dynamicRiskOptions: Option[],
  dynamicCourseTypeOptions: Option[]
): { id?: string | number; details?: any } {
  const rawTitle = (selectedCourse as any)?.title || (selectedCourse as any)?.name;
  const title = normalizeText(rawTitle || '');
  if (!title) return {};

  const source = (selectedCourseVariants && selectedCourseVariants.length > 0) ? selectedCourseVariants : trainings;
  const variants = (source as any[]).filter((t: any) => normalizeText(((t as any).title || (t as any).name) as string) === title);

  let filtered = variants;
  if (formData.risk_level) {
    filtered = filtered.filter((v: any) => String((v as any).riskLevel || '') === String(formData.risk_level));
  }
  if (formData.course_type) {
    filtered = filtered.filter((v: any) => String((v as any).courseType || '') === String(formData.course_type));
  }

  const hasRiskOptions = (dynamicRiskOptions?.length || 0) > 0;
  const hasTypeOptions = (dynamicCourseTypeOptions?.length || 0) > 0;

  if (filtered.length === 1) {
    const only = filtered[0] as any;
    return { id: only.id, details: only };
  }

  if (!hasRiskOptions && !hasTypeOptions && variants.length >= 1 && !formData.training_id) {
    const first = variants[0] as any;
    return { id: first.id, details: first };
  }

  return {};
}

export function deriveRequiredCerts(
  selectedCourse: any,
  selectedCourseVariants: any[] | undefined,
  trainings: any[],
  formData: { risk_level?: string; course_type?: string },
  normalizeText: (s: string) => string
): string[] {
  const directCerts = (selectedCourse as any)?.certifications as unknown;
  let certsFromSelected: string[] = [];
  if (Array.isArray(directCerts)) certsFromSelected = (directCerts as unknown[]).map(x => String(x)).filter(Boolean);
  else if (typeof directCerts === 'string') certsFromSelected = (directCerts as string).split(',').map(c => c.trim()).filter(Boolean);

  if ((certsFromSelected?.length || 0) > 0) return certsFromSelected;

  const rawTitle = (selectedCourse as any)?.title || (selectedCourse as any)?.name;
  const title = normalizeText(rawTitle || '');
  if (!title) return [] as string[];

  const source = (selectedCourseVariants && selectedCourseVariants.length > 0) ? selectedCourseVariants : trainings;
  const variants = (source as any[]).filter((t: any) => normalizeText(((t as any).title || (t as any).name) as string) === title);

  let filtered = variants;
  if (formData.risk_level) {
    filtered = filtered.filter((v: any) => String((v as any).riskLevel || '') === String(formData.risk_level));
  }
  if (formData.course_type) {
    filtered = filtered.filter((v: any) => String((v as any).courseType || '') === String(formData.course_type));
  }

  if (filtered.length === 0) return [] as string[];

  const lists: string[][] = filtered.map((v: any) => {
    const c = (v as any).certifications as unknown;
    if (Array.isArray(c)) return (c as unknown[]).map(s => String(s)).filter(Boolean);
    if (typeof c === 'string') return (c as string).split(',').map(s => s.trim()).filter(Boolean);
    return [] as string[];
  }).filter(arr => arr.length > 0);

  if (lists.length === 0) return [] as string[];
  if (lists.length === 1) return lists[0];

  const intersection = lists.reduce<string[]>((acc, curr) => acc.filter(x => curr.map(y => normalizeText(y)).includes(normalizeText(x))), lists[0]);
  if (intersection.length > 0) return Array.from(new Set(intersection));

  const union = Array.from(new Set(lists.flat()))
    .map(x => String(x))
    .filter(Boolean);
  return union;
}

export function getPersonIdsForCompanyUniversal(persons: Person[], companyId: string | number): (string | number)[] {
  const cid = String(companyId);
  return persons
    .filter((p) => {
      const pCompanyId = p.companyId ?? p.company?.id;
      return String(pCompanyId ?? '') === cid;
    })
    .map((p) => p.id)
    .filter((id): id is string | number => id !== undefined && id !== null);
}

